  /* ══════════════════════════════════════════════════════
     § 3 — EKONOMİ YÖNETİMİ
     ══════════════════════════════════════════════════════ */
  async function openGlobalEconModal() {
    _body(_section('💰 Ekonomi Kontrol Merkezi', `
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px">
        ${['genel','kripto','borsa','banka','pazar'].map(t=>`
          <button onclick="window.AP._econTab(this,'${t}')"
            style="background:${t==='genel'?'#1d4ed8':'#0d1a2e'};border:1px solid ${t==='genel'?'#3b82f6':'#1a2f4a'};color:${t==='genel'?'#fff':'#94a3b8'};padding:8px 16px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600"
            id="etab_${t}">
            ${{genel:'⚙️ Genel',kripto:'₿ Kripto',borsa:'📈 Borsa',banka:'🏦 Banka',pazar:'🛒 Pazar'}[t]}
          </button>`).join('')}
      </div>
      <div id="econTabContent"></div>
    `));
    _econTab(document.getElementById('etab_genel'), 'genel');
  }

  async function _econTab(el, tab) {
    document.querySelectorAll('[id^="etab_"]').forEach(b => {
      b.style.background='#0d1a2e'; b.style.borderColor='#1a2f4a'; b.style.color='#94a3b8';
    });
    if (el) { el.style.background='#1d4ed8'; el.style.borderColor='#3b82f6'; el.style.color='#fff'; }
    const div = document.getElementById('econTabContent');
    if (!div) return;
    div.innerHTML = '<div style="color:#475569;padding:20px">Yükleniyor...</div>';

    if (tab === 'genel') {
      const [vergi,kdFaiz,maxSatis,incMult,dBonus,sMoney,hvMult,prSpeed] = await Promise.all([
        _get('system/vergiOrani'),_get('system/krediDakikaFaiz'),_get('system/maxSatisBirimDongu'),
        _get('system/incomeMult'),_get('system/dailyBonus'),_get('system/startMoney'),
        _get('system/harvestMult'),_get('system/prodSpeedMult')
      ]);
      const inp = (id,ph,val,type='number',step=null) =>
        `<input type="${type}" id="${id}" placeholder="${ph}" value="${val||''}" ${step?`step="${step}"`:''}
          style="flex:1;min-width:80px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px">`;
      div.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px">

        <div style="background:#0d1a2e;border:1px solid #ef444433;border-radius:10px;padding:14px">
          <div style="font-size:11px;font-weight:700;color:#ef4444;margin-bottom:8px">🏛️ KDV / Satış Vergisi</div>
          <div style="display:flex;gap:6px;margin-bottom:4px">
            ${inp('gs_vergi','0.18',vergi||0.18,'number','0.01')}
            <button onclick="window.AP.setVergiOrani()" style="${_btnStyle('blue',true)}">Ayarla</button>
          </div>
          <div style="font-size:10px;color:#475569">= ${((vergi||0.18)*100).toFixed(0)}% — Tüm satışlardan kesilir</div>
        </div>

        <div style="background:#0d1a2e;border:1px solid #f59e0b33;border-radius:10px;padding:14px">
          <div style="font-size:11px;font-weight:700;color:#f59e0b;margin-bottom:8px">💳 Kredi Dakika Faizi</div>
          <div style="display:flex;gap:6px;margin-bottom:4px">
            ${inp('gs_kdFaiz','0.0000694',kdFaiz||0.0000694,'number','0.000001')}
            <button onclick="window.AP.setKrediDakikaFaiz()" style="${_btnStyle('blue',true)}">Kaydet</button>
          </div>
          <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:4px">
            ${[['%0.1/gün',0.0000694],['%0.2/gün',0.000139],['%0.5/gün',0.000347],['%1/gün',0.000694]].map(([l,v])=>
              `<button onclick="document.getElementById('gs_kdFaiz').value=${v}" style="${_btnStyle('yellow',true)}">${l}</button>`).join('')}
          </div>
        </div>

        ${[
          ['gs_maxSatis','Dükkan Satış Hızı (birim/döngü)','#22c55e',maxSatis||15,'setMaxSatisBirim'],
          ['gs_income_mult','Global Gelir Çarpanı (×)','#818cf8',incMult||1,'setGlobalSetting("incomeMult","gs_income_mult")'],
          ['gs_daily_bonus','Günlük Bonus (₺)','#fbbf24',dBonus||1000,'setGlobalSetting("dailyBonus","gs_daily_bonus")'],
          ['gs_start_money','Başlangıç Parası (₺)','#34d399',sMoney||10000,'setGlobalSetting("startMoney","gs_start_money")'],
          ['gs_harvest_mult','Hasat Çarpanı (×)','#a3e635',hvMult||1,'setGlobalSetting("harvestMult","gs_harvest_mult")'],
          ['gs_prod_speed','Üretim Hızı Çarpanı (×)','#14b8a6',prSpeed||1,'setGlobalSetting("prodSpeedMult","gs_prod_speed")'],
          ['gs_inflation','Enflasyon (tüm ürün +%)','#f97316',0,'applyInflation'],
        ].map(([id,label,clr,val,fn])=>`
          <div style="background:#0d1a2e;border:1px solid ${clr}22;border-radius:10px;padding:14px">
            <div style="font-size:11px;font-weight:700;color:${clr};margin-bottom:8px">${label}</div>
            <div style="display:flex;gap:6px">
              ${inp(id,'',val)}
              <button onclick="window.AP.${fn}()" style="${_btnStyle('blue',true)}">Ayarla</button>
            </div>
          </div>`).join('')}

      </div>`;

    } else if (tab === 'kripto') {
      const prices = await _get('crypto/prices')||{};
      const KRIPTO = window.KRIPTO||[];
      div.innerHTML = `
        <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;align-items:center">
          <input type="number" id="cryptoGlobalPct" placeholder="% değişim" style="width:120px;background:#0d1a2e;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px">
          <button onclick="window.AP.cryptoGlobalChange(1)" style="${_btnStyle('green',true)}">📈 Tümünü Artır</button>
          <button onclick="window.AP.cryptoGlobalChange(-1)" style="${_btnStyle('red',true)}">📉 Tümünü Düşür</button>
          <button onclick="window.AP.cryptoFreezeTrade(true)" style="${_btnStyle('orange',true)}">🔒 Ticareti Durdur</button>
          <button onclick="window.AP.cryptoFreezeTrade(false)" style="${_btnStyle('teal',true)}">🔓 Ticareti Aç</button>
        </div>
        ${_table(['Coin','Ad','Anlık Fiyat','Yeni Fiyat','İşlem'],
          KRIPTO.map(k=>{
            const cur=prices[k.sym]?.current||k.base;
            return [
              `<b>${k.emo} ${k.sym}</b>`,k.name,`₺${cur.toFixed(2)}`,
              `<input type="number" id="cp_${k.sym}" value="${cur.toFixed(2)}" style="width:90px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:4px;padding:4px 6px;font-size:11px">`,
              `<button onclick="window.AP.setCryptoPrice('${k.sym}')" style="${_btnStyle('blue',true)}">Ayarla</button>
               <button onclick="window.AP.lockCryptoPrice('${k.sym}',true)" style="${_btnStyle('red',true)}">🔒</button>
               <button onclick="window.AP.lockCryptoPrice('${k.sym}',false)" style="${_btnStyle('green',true)}">🔓</button>`
            ];
          })
        )}`;

    } else if (tab === 'borsa') {
      const STOCKS=window.STOCKS_DATA||[];
      div.innerHTML = `
        <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;align-items:center">
          <input type="number" id="stockGlobalPct" placeholder="% değişim" style="width:120px;background:#0d1a2e;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px">
          <button onclick="window.AP.stockGlobalChange(1)" style="${_btnStyle('green',true)}">📈 Artır</button>
          <button onclick="window.AP.stockGlobalChange(-1)" style="${_btnStyle('red',true)}">📉 Düşür</button>
          <button onclick="window.AP.triggerDividend()" style="${_btnStyle('yellow',true)}">💰 Temettü Dağıt</button>
        </div>
        <div id="stockPriceList"><div style="color:#475569">Hisseler yükleniyor...</div></div>`;
      _loadStockPrices();

    } else if (tab === 'banka') {
      div.innerHTML = `<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
        <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:10px;padding:14px">
          <div style="font-size:11px;font-weight:700;color:#34d399;margin-bottom:10px">🏦 Banka Ayarları</div>
          <div style="display:flex;gap:6px;margin-bottom:8px;align-items:center">
            <span style="font-size:12px;color:#94a3b8;white-space:nowrap">Faiz Oranı (%)</span>
            <input type="number" id="bankInterest" placeholder="0.3" step="0.1" style="flex:1;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:7px">
            <button onclick="window.AP.setBankInterest()" style="${_btnStyle('blue',true)}">Ayarla</button>
          </div>
          <div style="display:flex;gap:6px;margin-bottom:8px;align-items:center">
            <span style="font-size:12px;color:#94a3b8;white-space:nowrap">Kredi Çarpanı (Lv×?)</span>
            <input type="number" id="bankLoanMult" placeholder="5000" style="flex:1;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:7px">
            <button onclick="window.AP.setBankLoanMult()" style="${_btnStyle('blue',true)}">Ayarla</button>
          </div>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button onclick="window.AP.triggerInterestPayout()" style="${_btnStyle('yellow',true)}">💵 Faiz Öde (Manuel)</button>
            <button onclick="window.AP.collectOverdueLoans()" style="${_btnStyle('red',true)}">💳 Vadesi Geçmiş Tahsil</button>
          </div>
        </div>
      </div>`;

    } else if (tab === 'pazar') {
      div.innerHTML = `<div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:10px;padding:14px;max-width:500px">
        <div style="font-size:11px;font-weight:700;color:#f97316;margin-bottom:10px">🛒 Pazar Ayarları</div>
        <div style="display:flex;gap:6px;margin-bottom:8px;align-items:center">
          <span style="font-size:12px;color:#94a3b8;white-space:nowrap">Max Fiyat (₺)</span>
          <input type="number" id="marketMaxPrice" placeholder="1000000" style="flex:1;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:7px">
          <button onclick="window.AP.setMarketMaxPrice()" style="${_btnStyle('blue',true)}">Ayarla</button>
        </div>
        <div style="display:flex;gap:6px;margin-bottom:8px;align-items:center">
          <span style="font-size:12px;color:#94a3b8;white-space:nowrap">Komisyon (%)</span>
          <input type="number" id="marketCommission" placeholder="2" step="0.5" style="flex:1;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:7px">
          <button onclick="window.AP.setMarketCommission()" style="${_btnStyle('blue',true)}">Ayarla</button>
        </div>
        <button onclick="window.AP.clearAllListings()" style="${_btnStyle('red',true)};width:100%">🗑️ Tüm İlanları Temizle</button>
      </div>`;
    }
  }

  /* Ekonomi Fonksiyonları */
  async function setVergiOrani() {
    const v=safeNum(document.getElementById('gs_vergi')?.value); if(v<0||v>=1) return _toast('0-1 arası değer gir','error');
    await _set('system/vergiOrani',v); await _log('set_vergi',{v}); _toast(`🏛️ Vergi %${(v*100).toFixed(0)} ayarlandı`);
  }
  async function setKrediDakikaFaiz() {
    const v=safeNum(document.getElementById('gs_kdFaiz')?.value); if(v<=0) return _toast('Geçerli değer gir','error');
    await _set('system/krediDakikaFaiz',v); await _log('set_kredi_faiz',{v}); _toast(`💳 Dakika faizi ayarlandı`);
  }
  async function setMaxSatisBirim() {
    const v=safeNum(document.getElementById('gs_maxSatis')?.value); if(!v||v<1) return _toast('Geçerli değer gir','error');
    await _set('system/maxSatisBirimDongu',v); await _log('set_max_satis',{v}); _toast(`🏪 Satış hızı ${v} birim/döngü`);
  }
  async function setGlobalSetting(key, inputId) {
    const v=document.getElementById(inputId)?.value; if(!v) return _toast('Değer gir','error');
    const num=safeNum(v,null);
    await _set('system/'+key, num!==null?num:v); await _log('set_global_setting',{key,v}); _toast(`✅ ${key} kaydedildi`);
  }
  async function applyInflation() {
    const pct=safeNum(document.getElementById('gs_inflation')?.value); if(!pct) return _toast('% gir','error');
    if (!confirm(`Tüm ürün fiyatları %${pct} artırılacak!`)) return;
    const products = await _get('products')||{};
    const upd={};
    Object.keys(products).forEach(k=>{ if(products[k].price) upd['products/'+k+'/price']=Math.ceil(products[k].price*(1+pct/100)); });
    await db().ref().update(upd);
    await _log('apply_inflation',{pct}); _toast(`📈 %${pct} enflasyon uygulandı`);
  }
  async function setCryptoPrice(sym) {
    const v=safeNum(document.getElementById('cp_'+sym)?.value); if(!v||v<=0) return _toast('Geçerli fiyat gir','error');
    await _upd('crypto/prices/'+sym,{current:v,manualSet:true,setBy:'admin',setAt:TS()});
    await _log('set_crypto_price',{sym,v}); _toast(`${sym} → ₺${v.toFixed(2)}`);
  }
  async function lockCryptoPrice(sym,locked) {
    await _upd('crypto/prices/'+sym,{locked}); _toast(locked?`🔒 ${sym} kilitlendi`:`🔓 ${sym} serbest`);
  }
  async function cryptoGlobalChange(dir) {
    const pct=safeNum(document.getElementById('cryptoGlobalPct')?.value)/100*dir;
    if (!pct) return _toast('% gir','error');
    window.KRIPTO =window.KRIPTO||[]; const prices=await _get('crypto/prices')||{};
    const upd={};
    KRIPTO.forEach(k=>{
      const cur=prices[k.sym]?.current||k.base;
      upd['crypto/prices/'+k.sym+'/current']=Math.max(0.000001,cur*(1+pct));
      upd['crypto/prices/'+k.sym+'/prev']=cur;
      upd['crypto/prices/'+k.sym+'/changePct']=pct*100;
    });
    await db().ref().update(upd); await _log('crypto_global_change',{pct}); _toast(`₿ Tüm coinler ${pct>0?'+':''}${(pct*100).toFixed(1)}%`);
  }
  async function cryptoFreezeTrade(freeze) {
    await _set('system/cryptoTradeFrozen',freeze); _toast(freeze?'🔒 Kripto durduruldu':'🔓 Kripto açıldı');
  }
  async function _loadStockPrices() {
    const STOCKS=window.STOCKS_DATA||[]; const div=document.getElementById('stockPriceList'); if(!div) return;
    const pricePs=STOCKS.slice(0,15).map(s=>_get('stocks/prices/'+s.sym+'/current'));
    const prices=await Promise.all(pricePs);
    div.innerHTML=_table(['Sembol','Şirket','Anlık','Yeni Fiyat','İşlem'],
      STOCKS.slice(0,15).map((s,i)=>{
        const cur=prices[i]||s.basePrice;
        return [`<b>${s.sym}</b>`,s.name,`₺${cur.toFixed(2)}`,
          `<input type="number" id="sp_${s.sym}" value="${cur.toFixed(2)}" style="width:80px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:4px;padding:4px;font-size:11px">`,
          `<button onclick="window.AP.setStockPrice('${s.sym}')" style="${_btnStyle('blue',true)}">Ayarla</button>
           <button onclick="window.AP.lockStock('${s.sym}',true)" style="${_btnStyle('orange',true)}">🔒</button>`
        ];
      })
    );
  }
  async function setStockPrice(sym) {
    const v=safeNum(document.getElementById('sp_'+sym)?.value); if(!v||v<=0) return _toast('Geçerli fiyat gir','error');
    await _upd('stocks/prices/'+sym,{current:v,manualSet:true,setAt:TS()}); _toast(`${sym} → ₺${v.toFixed(2)}`);
  }
  async function lockStock(sym,locked) {
    await _upd('stocks/prices/'+sym,{locked}); _toast(locked?`🔒 ${sym} kilitlendi`:`🔓 ${sym} serbest`);
  }
  async function stockGlobalChange(dir) {
    const pct=safeNum(document.getElementById('stockGlobalPct')?.value)/100*dir; if(!pct) return _toast('% gir','error');
    const STOCKS=window.STOCKS_DATA||[]; const upd={};
    for (const s of STOCKS) {
      const cur=(await _get('stocks/prices/'+s.sym+'/current'))||s.basePrice;
      upd['stocks/prices/'+s.sym+'/current']=Math.max(0.01,cur*(1+pct));
    }
    await db().ref().update(upd); _toast(`📊 Tüm hisseler ${(pct*100).toFixed(1)}%`);
  }
  async function triggerDividend() {
    if (typeof window.distributeDividends==='function') { await window.distributeDividends(); _toast('💰 Temettü dağıtıldı'); }
    else _toast('distributeDividends bulunamadı','error');
  }
  async function setBankInterest() {
    const v=safeNum(document.getElementById('bankInterest')?.value); if(!v||v<0) return _toast('Oran gir','error');
    await _set('system/settings/bankInterestRate',v/100); await _log('set_bank_interest',{v}); _toast(`🏦 Faiz %${v}`);
  }
  async function setBankLoanMult() {
    const v=safeNum(document.getElementById('bankLoanMult')?.value); if(!v||v<1) return _toast('Çarpan gir','error');
    await _set('system/settings/bankLoanMult',v); await _log('set_loan_mult',{v}); _toast(`💳 Kredi çarpanı ${v}`);
  }
  async function triggerInterestPayout() {
    if (typeof window.applyBankInterest==='function') { await window.applyBankInterest(); _toast('💵 Faizler ödendi'); }
    else _toast('applyBankInterest bulunamadı','error');
  }
  async function collectOverdueLoans() {
    if (!confirm('Vadesi geçmiş krediler tahsil edilecek!')) return;
    if (typeof window.collectOverdue==='function') await window.collectOverdue();
    _toast('💳 Vadesi geçmiş krediler tahsil edildi');
  }
  async function setMarketMaxPrice() {
    const v=safeNum(document.getElementById('marketMaxPrice')?.value); if(!v||v<1) return _toast('Fiyat gir','error');
    await _set('system/settings/marketMaxPrice',v); _toast(`🛒 Max fiyat ${_fmt(v)}`);
  }
  async function setMarketCommission() {
    const v=safeNum(document.getElementById('marketCommission')?.value); if(v<0) return _toast('Komisyon gir','error');
    await _set('system/settings/marketCommission',v/100); _toast(`🛒 Komisyon %${v}`);
  }
  async function clearAllListings() {
    if (!confirm('Tüm pazar ilanları silinecek!')) return;
    await _rm('playerMarket'); await _log('clear_market',{}); _toast('🗑️ Pazar temizlendi');
  }

  /* ══════════════════════════════════════════════════════
     § 4 — KREDİ ONAY PANELİ
     ══════════════════════════════════════════════════════ */
  async function openKrediOnayPanel() {
    _body(_section('💳 Kredi Başvuruları', '<div id="kOnayContent" style="color:#60a5fa">Yükleniyor...</div>'));
    const snap = await db().ref('krediBasvurular').once('value');
    const all  = Object.values(snap.val()||{});
    const pend = all.filter(b=>b?.durum==='beklemede').sort((a,b)=>(b.ts||0)-(a.ts||0));
    const appr = all.filter(b=>b?.durum==='onaylandi').sort((a,b)=>(b.onayTs||0)-(a.onayTs||0)).slice(0,20);
    const rej  = all.filter(b=>b?.durum==='reddedildi').sort((a,b)=>(b.redTs||0)-(a.redTs||0)).slice(0,10);
    const el   = document.getElementById('kOnayContent'); if(!el) return;

    let h = `<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px">
      ${_statCard('⏳','Bekleyen',pend.length,'#f59e0b')}
      ${_statCard('✅','Onaylanan',appr.length,'#22c55e')}
      ${_statCard('❌','Reddedilen',rej.length,'#ef4444')}
    </div>
    <button onclick="window.AP.openKrediOnayPanel()" style="${_btnStyle('blue',true)};margin-bottom:14px">🔄 Yenile</button>`;

    if (!pend.length) {
      h += '<div style="background:#0d1a2e;border-radius:12px;padding:40px;text-align:center;color:#475569">✅ Bekleyen başvuru yok</div>';
    } else {
      h += `<div style="font-size:13px;font-weight:700;color:#f59e0b;margin-bottom:10px">⏳ Bekleyen (${pend.length})</div>`;
      h += pend.map(b => {
        const nr=b.krediNotu||0, nc=nr>=70?'#22c55e':nr>=50?'#f59e0b':'#ef4444';
        return `<div style="background:#0d1a2e;border:1px solid #f59e0b44;border-radius:12px;padding:16px;margin-bottom:10px">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px">
            <div>
              <div style="font-weight:700;color:#f1f5f9;font-size:16px">${_esc(b.username||b.uid)}</div>
              <div style="color:#475569;font-size:12px">${_esc(b.bankaAdi||b.bankaId||'?')} · Faiz: %${((b.faizOrani||0)*100).toFixed(1)}</div>
              ${b.aciklama?`<div style="color:#94a3b8;font-size:12px;font-style:italic;margin-top:2px">"${_esc(b.aciklama)}"</div>`:''}
            </div>
            <div style="text-align:right">
              <div style="font-size:26px;font-weight:900;color:#22c55e">₺${(b.miktar||0).toLocaleString('tr-TR')}</div>
              <div style="color:#475569;font-size:10px">${_time(b.ts)}</div>
            </div>
          </div>
          <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px">
            ${[['KREDİ NOTU',`<span style="color:${nc};font-weight:700">${b.krediNotu||'?'}/100</span>`],
               ['MEVCUT BORÇ',`<span style="color:#ef4444">₺${(b.mevcutBorc||0).toLocaleString()}</span>`],
               ['HAFTALIK FAİZ',`<span style="color:#f59e0b">₺${((b.miktar||0)*((b.faizOrani||0)/52)).toFixed(2)}</span>`],
               ['UID',`<span style="color:#334155;font-size:9px;font-family:monospace">${b.uid.slice(0,10)}…</span>`]
            ].map(([k,v])=>`<div style="background:#060c18;border-radius:8px;padding:8px;text-align:center">
              <div style="color:#475569;font-size:9px;font-weight:700">${k}</div>
              <div style="font-size:12px;margin-top:2px">${v}</div></div>`).join('')}
          </div>
          <div style="display:flex;gap:8px">
            <button data-uid="${b.uid}" data-bid="${b.bankaId}" data-mik="${b.miktar||0}"
              onclick="window._aKOnay(this)" style="${_btnStyle('green')};flex:1;text-align:center">✅ ONAYLA</button>
            <button data-uid="${b.uid}" data-bid="${b.bankaId}"
              onclick="window._aKReddet(this)" style="${_btnStyle('red')};flex:1;text-align:center">❌ REDDET</button>
            <button onclick="window.AP.openUserDetail('${b.uid}')" style="${_btnStyle('teal',true)}">👤</button>
          </div>
        </div>`;
      }).join('');
    }

    if (appr.length) {
      h += `<div style="font-size:13px;font-weight:700;color:#22c55e;margin:20px 0 10px">✅ Son Onaylananlar</div>`;
      h += _table(['Kullanıcı','Banka','Tutar','Haftalık Faiz','Tarih'],
        appr.map(b=>[`<b>${_esc(b.username||b.uid)}</b>`,_esc(b.bankaAdi||b.bankaId||'?'),
          `<span style="color:#22c55e">+₺${(b.miktar||0).toLocaleString()}</span>`,
          `<span style="color:#f59e0b">₺${((b.miktar||0)*((b.faizOrani||0)/52)).toFixed(2)}</span>`,
          _date(b.onayTs)]));
    }
    if (rej.length) {
      h += `<div style="font-size:13px;font-weight:700;color:#ef4444;margin:20px 0 10px">❌ Son Reddedilenler</div>`;
      h += _table(['Kullanıcı','Tutar','Sebep','Tarih'],
        rej.map(b=>[_esc(b.username||b.uid),`<span style="color:#ef4444">₺${(b.miktar||0).toLocaleString()}</span>`,
          _esc(b.redSebebi||'—'),_date(b.redTs)]));
    }
    el.innerHTML = h;
  }

  window._aKOnay = async function(btn) {
    const tuid=btn.getAttribute('data-uid'), bid=btn.getAttribute('data-bid'), mik=parseInt(btn.getAttribute('data-mik'))||0;
    if (!confirm(`₺${mik.toLocaleString('tr-TR')} kredi onaylanacak. Emin misin?`)) return;
    if (typeof window.krediOnayla==='function') { await window.krediOnayla(tuid,bid,mik,'Yönetici onayladı'); }
    else {
      await _tx('bank/'+tuid+'/loan',c=>(c||0)+mik);
      await _tx('users/'+tuid+'/money',c=>(c||0)+mik);
      await db().ref('krediBasvurular/'+tuid+'_'+bid).update({durum:'onaylandi',onaylayanNot:'Yönetici',onayTs:TS()});
    }
    await _notify(tuid,'✅ Kredi başvurunuz onaylandı! ₺'+mik.toLocaleString()+' hesabınıza eklendi.','✅');
    _toast('✅ ₺'+mik.toLocaleString()+' onaylandı'); window.AP.openKrediOnayPanel(); _checkKrediOnayBadge();
  };
  window._aKReddet = async function(btn) {
    const tuid=btn.getAttribute('data-uid'), bid=btn.getAttribute('data-bid');
    const sebep=prompt('Red sebebi:')||'Yönetici reddetti';
    if (typeof window.krediReddet==='function') { await window.krediReddet(tuid,bid,sebep); }
    else { await db().ref('krediBasvurular/'+tuid+'_'+bid).update({durum:'reddedildi',redSebebi:sebep,redTs:TS()}); }
    await _notify(tuid,'❌ Kredi başvurunuz reddedildi. Sebep: '+sebep,'❌');
    _toast('Başvuru reddedildi'); window.AP.openKrediOnayPanel(); _checkKrediOnayBadge();
  };

  /* ══════════════════════════════════════════════════════
     § 5 — VERGİ & FAİZ PANELİ
     ══════════════════════════════════════════════════════ */
  async function openVergiPanel() {
    _body(_section('🏛️ Vergi & Faiz Yönetimi', '<div id="vergiContent" style="color:#60a5fa">Yükleniyor...</div>'));
    const [rates, logSnap, bankFaizler] = await Promise.all([
      _get('system/merkezBankasi'),
      db().ref('system/merkezBankasi/vergiLog').orderByKey().limitToLast(30).once('value'),
      _get('system/bankFaizler')
    ]);
    const loglar = Object.values(logSnap.val()||{}).reverse();
    const el = document.getElementById('vergiContent'); if(!el) return;

    window.BANKALAR = ['ziraat','vakif','halk','is','garanti','akbank','ykb','qnb','deniz','teb'];
    const bankFaiz = bankFaizler||{};

    el.innerHTML = `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px">

        <!-- Vergi Tarifeleri -->
        <div style="background:#0d1a2e;border:1px solid #f59e0b33;border-radius:12px;padding:16px">
          <div style="font-size:12px;font-weight:700;color:#f59e0b;margin-bottom:12px">🏛️ Vergi Tarifeleri (%)</div>
          ${[['shopTax','Dükkan'],['gardenTax','Bahçe'],['farmTax','Çiftlik'],['factoryTax','Fabrika'],['mineTax','Maden'],['gelirOrani','Gelir Vergisi']].map(([k,l])=>`
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
              <span style="color:#94a3b8;font-size:12px">${l}</span>
              <input type="number" id="vt_${k}" value="${rates?.[k]||0}" min="0" max="100" step="1"
                style="width:70px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:5px;font-size:12px;text-align:right">
            </div>`).join('')}
          <button onclick="window._saveVergiRates()" style="${_btnStyle('green')};width:100%;margin-top:4px">💾 Tarifeleri Kaydet</button>
        </div>

        <!-- Banka Faiz Oranları -->
        <div style="background:#0d1a2e;border:1px solid #22c55e33;border-radius:12px;padding:16px">
          <div style="font-size:12px;font-weight:700;color:#22c55e;margin-bottom:12px">🏦 Banka Faiz Oranları</div>
          ${BANKALAR.map(id=>`
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
              <span style="color:#94a3b8;font-size:12px;text-transform:capitalize">${id}</span>
              <div style="display:flex;align-items:center;gap:4px">
                <span style="color:#475569;font-size:10px">%${((bankFaiz[id]||0)*100).toFixed(2)}</span>
                <input type="number" id="bf_${id}" value="${((bankFaiz[id]||0)*100).toFixed(2)}" min="0" max="100" step="0.1"
                  style="width:70px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:5px;font-size:12px;text-align:right">
              </div>
            </div>`).join('')}
          <button onclick="window._saveBankFaizler()" style="${_btnStyle('green')};width:100%;margin-top:4px">💾 Faiz Kaydet</button>
        </div>
      </div>

      <!-- Son Vergi Kayıtları -->
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
        <div style="font-size:12px;font-weight:700;color:#94a3b8;margin-bottom:10px">📋 Son Vergi Kayıtları</div>
        ${loglar.length ? _table(['Kullanıcı','Vergi','Faiz','Detay','Tarih'],
          loglar.map(l=>[
            `<b>${_esc(l.username||l.uid||'—')}</b>`,
            `<span style="color:#f59e0b">₺${(l.vergi||0).toLocaleString()}</span>`,
            `<span style="color:#22c55e">₺${(l.faiz||0).toLocaleString()}</span>`,
            l.detay?Object.entries(l.detay).filter(([,v])=>v>0).map(([k,v])=>`${k}:${v}`).join(', '):'—',
            _date(l.ts)
          ])
        ) : '<div style="text-align:center;color:#475569;padding:20px">Kayıt yok</div>'}
      </div>`;
  }

  window._saveVergiRates = async function() {
    const upd={};
    ['shopTax','gardenTax','farmTax','factoryTax','mineTax'].forEach(k=>{
      const v=parseInt(document.getElementById('vt_'+k)?.value)||0; upd['system/merkezBankasi/rates_'+k]=v;
    });
    const gelir=parseFloat(document.getElementById('vt_gelirOrani')?.value)||8; upd['system/merkezBankasi/gelirOrani']=gelir;
    await db().ref().update(upd); _toast('💾 Vergi tarifeleri kaydedildi'); await _log('save_vergi_rates',upd);
  };
  window._saveBankFaizler = async function() {
    const upd={};
    ['ziraat','vakif','halk','is','garanti','akbank','ykb','qnb','deniz','teb'].forEach(id=>{
      const v=parseFloat(document.getElementById('bf_'+id)?.value)||0; upd['system/bankFaizler/'+id]=v/100;
    });
    await db().ref().update(upd);
    if (window.BANKALAR_MAP) Object.entries(upd).forEach(([path,v])=>{ const id=path.split('/').pop(); if(window.BANKALAR_MAP[id]) window.BANKALAR_MAP[id].faiz=v; });
    _toast('💾 Faiz oranları kaydedildi'); await _log('save_faiz_rates',upd);
  };

  /* ══════════════════════════════════════════════════════
     § 6 — MERKEZ BANKASI PANELİ
     ══════════════════════════════════════════════════════ */
  async function openMerkezBankasiPanel() {
    _body(_section('🏦 Merkez Bankası', '<div id="mbContent" style="color:#60a5fa">Yükleniyor...</div>'));
    const authUid   = await _get('system/authorityUid');
    const authMoney = authUid?(await _get('users/'+authUid+'/money'))||0:0;
    const mb        = (await _get('system/merkezBankasi'))||{};
    const logSnap   = await db().ref('system/merkezBankasi/vergiLog').orderByKey().limitToLast(30).once('value');
    const loglar    = Object.values(logSnap.val()||{}).reverse();
    const allUsers  = (await _get('users'))||{};
    const el        = document.getElementById('mbContent'); if(!el) return;

    // Borçlu listesi
    const borrowers=[];
    for(const [id,u] of Object.entries(allUsers)){
      const bank=(await _get('bank/'+id))||{};
      if((bank.loan||0)>0) borrowers.push({uid:id,username:u.username||id,loan:bank.loan||0,krediNotu:u.krediNotu||100});
    }
    borrowers.sort((a,b)=>b.loan-a.loan);

    el.innerHTML = `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:20px">
        <div style="background:linear-gradient(135deg,#0d1a2e,#0d2240);border:1px solid #1e3a5f;border-radius:14px;padding:20px">
          <div style="color:#94a3b8;font-size:10px;letter-spacing:1.5px">HAZİNE BAKİYESİ</div>
          <div style="color:#22c55e;font-weight:900;font-size:32px;margin-top:4px">₺${authMoney.toLocaleString('tr-TR',{minimumFractionDigits:2})}</div>
          <div style="color:#334155;font-size:11px;margin-top:4px">Yetkili Hesabı</div>
        </div>
        <div style="background:linear-gradient(135deg,#0d1a2e,#1a0d2e);border:1px solid #2d1a5f;border-radius:14px;padding:20px">
          <div style="color:#94a3b8;font-size:10px;letter-spacing:1.5px">TOPLAM GELİR</div>
          <div style="color:#a855f7;font-weight:900;font-size:32px;margin-top:4px">₺${((mb.totalVergi||0)+(mb.totalFaiz||0)).toLocaleString('tr-TR',{minimumFractionDigits:2})}</div>
          <div style="color:#334155;font-size:11px;margin-top:4px">Vergi + Faiz Toplamı</div>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
        <!-- Para Gönder -->
        <div style="background:#0d1a2e;border:1px solid #22c55e33;border-radius:12px;padding:14px">
          <div style="font-size:12px;font-weight:700;color:#22c55e;margin-bottom:10px">💸 Hazineden Para Gönder</div>
          <input type="text" id="mbToUid" placeholder="UID veya kullanıcı adı"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px;margin-bottom:6px">
          <input type="number" id="mbAmount" placeholder="Miktar (₺)"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px;margin-bottom:8px">
          <button onclick="window._mbGonder()" style="${_btnStyle('green')};width:100%">💸 Gönder</button>
        </div>

        <!-- Manuel Vergi Tahsil -->
        <div style="background:#0d1a2e;border:1px solid #f59e0b33;border-radius:12px;padding:14px">
          <div style="font-size:12px;font-weight:700;color:#f59e0b;margin-bottom:10px">🏛️ Manuel Vergi Tahsil</div>
          <input type="text" id="mbTaxUid" placeholder="UID veya kullanıcı adı"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px;margin-bottom:6px">
          <div id="mbTaxPreview" style="color:#475569;font-size:11px;min-height:20px;margin-bottom:8px"></div>
          <div style="display:flex;gap:6px">
            <button onclick="window._mbTaxPreview()" style="${_btnStyle('teal',true)};flex:1">🔍 Hesapla</button>
            <button onclick="window._mbTaxCollect()" style="${_btnStyle('yellow',true)};flex:1">Tahsil Et</button>
          </div>
        </div>
      </div>

      <!-- Borçlular -->
      <div style="background:#0d1a2e;border:1px solid #ef444433;border-radius:12px;padding:14px;margin-bottom:14px">
        <div style="font-size:12px;font-weight:700;color:#ef4444;margin-bottom:10px">💳 Borçlu Kullanıcılar (${borrowers.length})</div>
        ${borrowers.length ? _table(['Kullanıcı','Borç','Kredi Notu','İşlem'],
          borrowers.map(b=>[
            `<b>${_esc(b.username)}</b>`,
            `<span style="color:#ef4444;font-weight:700">₺${b.loan.toLocaleString()}</span>`,
            `<span style="color:${b.krediNotu>=70?'#22c55e':b.krediNotu>=50?'#f59e0b':'#ef4444'}">${b.krediNotu}/100</span>`,
            `<button onclick="window._mbBorcSil('${b.uid}')" style="${_btnStyle('green',true)}">Sil</button>
             <button onclick="window._mbBorcTahsil('${b.uid}',${b.loan})" style="${_btnStyle('yellow',true)}">Tahsil</button>`
          ])
        ) : '<div style="text-align:center;color:#475569;padding:16px">Borçlu kullanıcı yok ✅</div>'}
      </div>

      <!-- Son loglar -->
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:14px">
        <div style="font-size:12px;font-weight:700;color:#94a3b8;margin-bottom:10px">📋 Son İşlem Kayıtları</div>
        ${loglar.length ? _table(['Kullanıcı','Vergi','Faiz','Toplam','Tarih'],
          loglar.map(l=>[
            `<b>${_esc(l.username||l.uid||'—')}</b>`,
            `<span style="color:#f59e0b">₺${(l.vergi||0).toLocaleString()}</span>`,
            `<span style="color:#22c55e">₺${(l.faiz||0).toLocaleString()}</span>`,
            `<span style="color:#3b82f6;font-weight:700">₺${((l.vergi||0)+(l.faiz||0)).toLocaleString()}</span>`,
            _date(l.ts)
          ])
        ) : '<div style="text-align:center;color:#475569;padding:16px">Kayıt yok</div>'}
      </div>`;
  }

  window._mbGonder = async function() {
    const inp=document.getElementById('mbToUid')?.value?.trim(), mik=parseFloat(document.getElementById('mbAmount')?.value)||0;
    if(!inp||mik<=0) return _toast('Alıcı ve miktar gir','warn');
    let tuid=inp;
    const ud=await _get('users/'+inp);
    if(!ud){const s=await db().ref('users').orderByChild('username').equalTo(inp).once('value');const f=s.val();if(f)tuid=Object.keys(f)[0];else return _toast('Kullanıcı bulunamadı','error');}
    const authUid=await _get('system/authorityUid'); if(!authUid) return _toast('Hazine UID yok','error');
    const bal=(await _get('users/'+authUid+'/money'))||0; if(bal<mik) return _toast('Hazine yetersiz!','error');
    await db().ref('users/'+authUid+'/money').transaction(c=>(c||0)-mik);
    await db().ref('users/'+tuid+'/money').transaction(c=>(c||0)+mik);
    await _notify(tuid,'💸 Hazineden ₺'+mik.toLocaleString()+' transferi alındı.','💸');
    _toast('✅ ₺'+mik.toLocaleString()+' gönderildi'); await _log('mb_gonder',{to:tuid,amount:mik}); window.AP.openMerkezBankasiPanel();
  };
  window._mbTaxPreview = async function() {
    const inp=document.getElementById('mbTaxUid')?.value?.trim(), el=document.getElementById('mbTaxPreview');
    if(!inp||!el) return;
    let tuid=inp; const ud=await _get('users/'+inp);
    if(!ud){const s=await db().ref('users').orderByChild('username').equalTo(inp).once('value');const f=s.val();if(f)tuid=Object.keys(f)[0];else{el.textContent='Kullanıcı bulunamadı';return;}}
    if(typeof window.getVergiDetay==='function'){
      const v=await window.getVergiDetay(tuid);
      el.innerHTML=`<span style="color:#f59e0b">Vergi: ₺${v.totalVergi}</span> + <span style="color:#22c55e">Faiz: ₺${v.weeklyFaiz}</span> = <b style="color:#e2e8f0">₺${v.totalVergi+v.weeklyFaiz}</b>`;
      el.dataset.uid=tuid;
    }
  };
  window._mbTaxCollect = async function() {
    const el=document.getElementById('mbTaxPreview'), tuid=el?.dataset?.uid;
    if(!tuid) return _toast("Önce Hesapla'ya bas",'warn');
    const authUid=await _get('system/authorityUid');
    if(typeof window.getVergiDetay==='function'){
      const v=await window.getVergiDetay(tuid); const toplam=v.totalVergi+v.weeklyFaiz;
      if(toplam<=0) return _toast('Tahsil edilecek şey yok','warn');
      await db().ref('users/'+tuid+'/money').transaction(c=>Math.max(0,(c||0)-toplam));
      if(authUid) await db().ref('users/'+authUid+'/money').transaction(c=>(c||0)+toplam);
      _toast('✅ ₺'+toplam.toLocaleString()+' tahsil edildi'); window.AP.openMerkezBankasiPanel();
    }
  };
  window._mbBorcSil = async function(tuid) {
    if(!confirm('Borç sıfırlanacak. Emin misin?')) return;
    await _set('bank/'+tuid+'/loan',0); if(typeof window.updateKrediNotu==='function') await window.updateKrediNotu(tuid,5,'Admin borç sildi');
    _toast('✅ Borç silindi'); window.AP.openMerkezBankasiPanel();
  };
  window._mbBorcTahsil = async function(tuid,borc) {
    if(!confirm('₺'+borc.toLocaleString()+' tahsil edilecek. Emin misin?')) return;
    const ok=await db().ref('users/'+tuid+'/money').transaction(c=>{if((c||0)<borc)return;return c-borc;});
    const authUid=await _get('system/authorityUid');
    if(ok.committed){
      await _set('bank/'+tuid+'/loan',0); if(authUid) await db().ref('users/'+authUid+'/money').transaction(c=>(c||0)+borc);
      _toast('✅ ₺'+borc.toLocaleString()+' tahsil edildi');
    } else {await _set('bank/'+tuid+'/loan',0); _toast('Bakiye yetersiz — borç silindi','warn');}
    window.AP.openMerkezBankasiPanel();
  };

  /* ══════════════════════════════════════════════════════
     § 7 — HABERLER YÖNETİMİ
     ══════════════════════════════════════════════════════ */
  async function openNewsManager() {
    _body(_section('📰 Haberler & Duyurular', `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
        <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
          <div style="font-size:12px;font-weight:700;color:#3b82f6;margin-bottom:12px">📝 Yeni Haber</div>
          <input type="text" id="news_title" placeholder="Başlık"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px;margin-bottom:8px">
          <textarea id="news_body" rows="4" placeholder="İçerik..."
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px 10px;font-size:12px;resize:vertical;font-family:inherit;margin-bottom:8px"></textarea>
          <div style="display:flex;gap:6px;margin-bottom:8px">
            <select id="news_cat" style="flex:1;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px">
              <option value="update">🔄 Güncelleme</option>
              <option value="event">🎉 Etkinlik</option>
              <option value="maintenance">🔧 Bakım</option>
              <option value="announcement">📢 Duyuru</option>
            </select>
            <input type="text" id="news_icon" placeholder="İkon" value="📢"
              style="width:60px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px">
          </div>
          <button onclick="window.AP.publishNews()" style="${_btnStyle('green')};width:100%">📢 Yayınla</button>
        </div>
        <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
            <div style="font-size:12px;font-weight:700;color:#94a3b8">📋 Mevcut Haberler</div>
            <button onclick="window.AP.openNewsManager()" style="${_btnStyle('blue',true)}">🔄</button>
          </div>
          <div id="newsList" style="color:#475569">Yükleniyor...</div>
        </div>
      </div>`));
    _loadNewsList();
  }

  async function _loadNewsList() {
    const div=document.getElementById('newsList'); if(!div) return;
    const news=await _get('news')||{};
    const entries=Object.entries(news).sort((a,b)=>(b[1].ts||0)-(a[1].ts||0));
    div.innerHTML = entries.length ? entries.map(([id,n])=>`
      <div style="border-bottom:1px solid #0a1628;padding:8px 0;display:flex;align-items:center;gap:8px">
        <span style="font-size:18px">${n.icon||'📢'}</span>
        <div style="flex:1;min-width:0">
          <div style="color:#e2e8f0;font-size:12px;font-weight:600">${_esc(n.title||'—')}</div>
          <div style="color:#475569;font-size:10px">${_date(n.ts)} · ${n.category||'?'}</div>
        </div>
        <button onclick="window.AP.deleteNews('${id}')" style="${_btnStyle('red',true)}">🗑️</button>
        <button onclick="window.AP.toggleNewsVisibility('${id}',${!n.hidden})" style="${_btnStyle(n.hidden?'green':'orange',true)}">${n.hidden?'👁️ Göster':'🙈 Gizle'}</button>
      </div>`).join('') : '<div style="text-align:center;color:#475569;padding:20px">Haber yok</div>';
  }

  async function publishNews() {
    const title=document.getElementById('news_title')?.value?.trim(), body=document.getElementById('news_body')?.value?.trim();
    const cat=document.getElementById('news_cat')?.value, icon=document.getElementById('news_icon')?.value||'📢';
    if(!title||!body) return _toast('Başlık ve içerik gir','error');
    await _push('news',{title,body,category:cat,icon,ts:TS(),author:uid(),hidden:false});
    await _log('publish_news',{title}); _toast('📢 Haber yayınlandı'); openNewsManager();
  }
  async function deleteNews(id) {
    if (!confirm('Haber silinecek!')) return; await _rm('news/'+id); _toast('🗑️ Silindi'); _loadNewsList();
  }
  async function toggleNewsVisibility(id, hidden) {
    await _upd('news/'+id,{hidden}); _toast(hidden?'🙈 Gizlendi':'👁️ Gösterildi'); _loadNewsList();
  }

