  async function setSystemSetting(key,inputId) {
    const v=document.getElementById(inputId)?.value?.trim(); if(!v) return _toast('Değer gir','error');
    await _set('system/settings/'+key,v); await _log('set_system_setting',{key,v}); _toast(`✅ ${key} kaydedildi`);
  }
  async function setElmasFiyati() {
    const v=safeNum(document.getElementById('sys_elmas_fiyat')?.value); if(!v||v<1) return _toast('Geçerli fiyat gir (min: 1₺)','error');
    await _set('system/elmasFiyati',v); await _notifyAll(`💎 Elmas fiyatı güncellendi: 1 💎 = ${_fmt(v)}`, '💎');
    await _log('set_elmas_fiyati',{fiyat:v}); _toast(`💎 1 Elmas = ${_fmt(v)}`);
  }
  async function toggleRegistration(open) {
    await _set('system/settings/registrationOpen',open); await _log('toggle_registration',{open}); _toast(open?'✅ Kayıt açıldı':'🔒 Kayıt kapatıldı');
  }
  async function toggleAnon(open) {
    await _set('system/settings/anonLoginOpen',open); _toast(open?'✅ Anonim giriş açıldı':'🔒 Anonim giriş kapatıldı');
  }
  async function toggleMaintenanceMode() {
    const cur=await _get('system/settings/maintenance'); const next=!cur;
    await _set('system/settings/maintenance',next); await _log('toggle_maintenance',{next}); _toast(next?'🔧 Bakım modu AÇıldı':'✅ Bakım modu kapatıldı');
  }
  async function applyThemeColor(type,inputId) {
    const v=document.getElementById(inputId)?.value; if(!v) return;
    await _set('system/theme/'+type,v); _toast(`🎨 Renk güncellendi`);
  }
  async function applySeasonTheme() {
    const v=document.getElementById('theme_season')?.value;
    await _set('system/seasonTheme',v||null); _toast(`🌸 Sezon teması: ${v||'Varsayılan'}`);
  }
  async function clearAllAlerts() {
    await _rm('adminAlerts'); _toast('🗑️ Alertler temizlendi');
  }
  async function backupDatabase() {
    _toast('💾 Snapshot Firebase konsolundan alınabilir (Rules > Backups)', 'info', 5000);
  }

  /* ══════════════════════════════════════════════════════
     § 13 — ANALİTİK
     ══════════════════════════════════════════════════════ */
  async function openAnalytics() {
    _body(_section('📈 Analitik & Raporlar', `
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px">
        ${['player','economy','tech'].map((t,i)=>`
          <button onclick="window.AP._anaTab(this,'${t}')"
            id="atab_${t}"
            style="background:${i===0?'#1d4ed8':'#0d1a2e'};border:1px solid ${i===0?'#3b82f6':'#1a2f4a'};color:${i===0?'#fff':'#94a3b8'};padding:8px 14px;border-radius:8px;cursor:pointer;font-size:12px;font-weight:600">
            ${{player:'👥 Oyuncu',economy:'💰 Ekonomi',tech:'🔧 Teknik'}[t]}
          </button>`).join('')}
      </div>
      <div id="anaTabContent"></div>`));
    _anaTab(document.getElementById('atab_player'),'player');
  }

  async function _anaTab(el,tab) {
    document.querySelectorAll('[id^="atab_"]').forEach(b=>{b.style.background='#0d1a2e';b.style.borderColor='#1a2f4a';b.style.color='#94a3b8';});
    if(el){el.style.background='#1d4ed8';el.style.borderColor='#3b82f6';el.style.color='#fff';}
    const div=document.getElementById('anaTabContent'); if(!div) return;
    div.innerHTML='<div style="color:#475569;padding:20px">Analiz yapılıyor...</div>';

    if(tab==='player') await loadPlayerAnalytics();
    else if(tab==='economy') await loadEconomyAnalytics();
    else if(tab==='tech') await loadTechAnalytics();
  }

  async function loadPlayerAnalytics() {
    const div=document.getElementById('anaTabContent'); if(!div) return;
    const users=await _get('users')||{};
    const uids=Object.keys(users), totalUsers=uids.length, now=Date.now(), DAY=86400000;
    const day1    = uids.filter(u=>users[u].createdAt&&(now-users[u].createdAt)<DAY).length;
    const day7    = uids.filter(u=>users[u].lastLogin&&(now-users[u].lastLogin)<7*DAY).length;
    const day30   = uids.filter(u=>users[u].lastLogin&&(now-users[u].lastLogin)<30*DAY).length;
    const day14In = uids.filter(u=>!users[u].lastLogin||(now-users[u].lastLogin)>14*DAY).length;
    const lvlGrps = {'1-10':0,'11-25':0,'26-50':0,'51-75':0,'76-100':0,'100+':0};
    uids.forEach(u=>{const lv=users[u].level||1;if(lv<=10)lvlGrps['1-10']++;else if(lv<=25)lvlGrps['11-25']++;else if(lv<=50)lvlGrps['26-50']++;else if(lv<=75)lvlGrps['51-75']++;else if(lv<=100)lvlGrps['76-100']++;else lvlGrps['100+']++;});

    div.innerHTML=`<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
        <div style="font-size:12px;font-weight:700;color:#3b82f6;margin-bottom:10px">📊 Tutundurma</div>
        ${[['Bugün Yeni Kayıt',day1,'#f59e0b'],['7g Aktif (WAU)',day7,'#22c55e'],['30g Aktif (MAU)',day30,'#3b82f6'],
           ['14g+ İnaktif',day14In,'#ef4444'],['7g Tutundurma',totalUsers?((day7/totalUsers)*100).toFixed(1)+'%':'0%','#a78bfa'],
           ['30g Tutundurma',totalUsers?((day30/totalUsers)*100).toFixed(1)+'%':'0%','#818cf8']
        ].map(([l,v,c])=>`<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #0a1628">
          <span style="color:#475569;font-size:12px">${l}</span>
          <span style="color:${c};font-weight:700;font-size:12px">${v}</span></div>`).join('')}
      </div>
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
        <div style="font-size:12px;font-weight:700;color:#c084fc;margin-bottom:10px">🏅 Seviye Dağılımı</div>
        ${Object.entries(lvlGrps).map(([range,count])=>`
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
            <span style="color:#475569;font-size:11px;width:50px">Lv ${range}</span>
            <div style="flex:1;height:12px;background:#060c18;border-radius:99px;overflow:hidden">
              <div style="height:100%;background:#3b82f6;border-radius:99px;transition:.5s;width:${totalUsers?Math.floor(count/totalUsers*100):0}%"></div>
            </div>
            <span style="color:#e2e8f0;font-size:11px;font-weight:600;width:24px;text-align:right">${count}</span>
          </div>`).join('')}
      </div>
    </div>`;
  }

  async function loadEconomyAnalytics() {
    const div=document.getElementById('anaTabContent'); if(!div) return;
    const [users,bank,finSnap] = await Promise.all([_get('users'),_get('bank'),_get('financeLog')]);
    const uids=Object.keys(users||{});
    const totalMoney=uids.reduce((s,u)=>(users[u].money||0)+s,0);
    const finLogs=Object.values(finSnap||{});
    const now=Date.now(),DAY=86400000;
    const todayTax=finLogs.filter(l=>l.ts&&(now-l.ts)<DAY).reduce((s,l)=>s+(l.tax||0),0);
    const weekTax=finLogs.filter(l=>l.ts&&(now-l.ts)<7*DAY).reduce((s,l)=>s+(l.tax||0),0);
    let totalBank=0,totalDebt=0;
    Object.values(bank||{}).forEach(b=>{if(b){totalBank+=b.balance||0;totalDebt+=b.loan||0;}});

    div.innerHTML=`<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px">
      ${[['💰','Dolaşım',_fmt(totalMoney),'#eab308'],['🏦','Banka Mevduat',_fmt(totalBank),'#34d399'],
         ['💳','Toplam Borç',_fmt(totalDebt),'#ef4444'],['📉','Bugün Vergi',_fmt(todayTax),'#22d3ee'],
         ['📉','Hafta Vergi',_fmt(weekTax),'#22d3ee'],['💵','Kişi Başı',uids.length?_fmt(totalMoney/uids.length):'0','#fbbf24']
      ].map(([i,l,v,c])=>_statCard(i,l,v,c)).join('')}
    </div>`;
  }

  async function loadTechAnalytics() {
    const div=document.getElementById('anaTabContent'); if(!div) return;
    const [logs,security] = await Promise.all([_get('adminLogs'),_get('security/founderAttempts')]);
    const allLogs=Object.values(logs||{}), allSec=Object.values(security||{});

    div.innerHTML=`<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
        <div style="font-size:12px;font-weight:700;color:#34d399;margin-bottom:10px">🔧 Sistem Sağlığı</div>
        ${[['Firebase','<span style="color:#22c55e;font-weight:700">✅ Bağlı</span>'],
           ['Toplam Admin İşlemi',allLogs.length],['Giriş Denemesi',allSec.length],
           ['Başarılı Admin Giriş',allSec.filter(s=>s.success).length],
           ['Başarısız Admin Giriş',`<span style="color:#ef4444">${allSec.filter(s=>!s.success).length}</span>`]
        ].map(([k,v])=>`<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #0a1628">
          <span style="color:#475569;font-size:12px">${k}</span>
          <span style="color:#e2e8f0;font-size:12px;font-weight:600">${v}</span></div>`).join('')}
      </div>
      <div style="background:#0d1a2e;border:1px solid #1a2f4a;border-radius:12px;padding:16px">
        <div style="font-size:12px;font-weight:700;color:#94a3b8;margin-bottom:10px">📋 Son Admin İşlemleri</div>
        ${allLogs.sort((a,b)=>(b.ts||0)-(a.ts||0)).slice(0,15).map(l=>`
          <div style="display:flex;gap:8px;padding:4px 0;border-bottom:1px solid #0a1628">
            <span style="color:#334155;font-size:10px;white-space:nowrap">${_time(l.ts)}</span>
            <span style="color:#60a5fa;font-size:11px;font-weight:600">${_esc(l.action)}</span>
          </div>`).join('')}
      </div>
    </div>`;
  }

