  function openBroadcastModal() {
    _modal('📢 Duyuru Yayınla', `
      <div style="padding:4px">
        <div style="margin-bottom:14px">
          <div style="font-size:11px;color:#94a3b8;margin-bottom:6px">📝 DUYURU METNİ</div>
          <textarea id="bc_text" placeholder="Tüm oyunculara gönderilecek mesaj..." rows="3"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px;resize:vertical;font-family:inherit;margin-bottom:6px"></textarea>
          <div style="display:flex;gap:6px;align-items:center">
            <span style="color:#94a3b8;font-size:12px">Süre (dk)</span>
            <input type="number" id="bc_dur" value="30" style="width:70px;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:6px;font-size:12px">
            <button onclick="window.AP.sendBroadcast()" style="${_btnStyle('green')};flex:1">📢 Tüm Oyunculara Yayınla</button>
            <button onclick="window.AP.clearBroadcast()" style="${_btnStyle('red',true)}">Kaldır</button>
          </div>
        </div>

        <hr style="border:none;border-top:1px solid #1a2f4a;margin:14px 0">

        <div>
          <div style="font-size:11px;color:#94a3b8;margin-bottom:6px">📨 SEGMENT BİLDİRİMİ</div>
          <select id="bc_segment" style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px;margin-bottom:6px">
            <option value="all">Tüm Oyuncular</option>
            <option value="vip">Sadece VIP</option>
            <option value="lv10plus">Lv 10+</option>
            <option value="lv25plus">Lv 25+</option>
            <option value="lv50plus">Lv 50+</option>
            <option value="inactive">14g İnaktif</option>
            <option value="new">Yeni (7g içinde)</option>
          </select>
          <textarea id="bc_seg_text" placeholder="Bildirim metni..." rows="2"
            style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px;resize:vertical;font-family:inherit;margin-bottom:6px"></textarea>
          <button onclick="window.AP.sendSegmentNotif()" style="${_btnStyle('blue')};width:100%">📨 Segment Bildirimi Gönder</button>
        </div>
      </div>`, true);
  }

  async function sendBroadcast() {
    const text=document.getElementById('bc_text')?.value?.trim(), dur=safeNum(document.getElementById('bc_dur')?.value,30);
    if(!text) return _toast('Duyuru metni boş','error');
    await _set('broadcast/current',{active:true,text,sentAt:TS(),expiresAt:Date.now()+dur*60*1000});
    await _push('broadcast/history',{text,sentAt:TS(),dur});
    await _log('broadcast',{text:text.slice(0,100),dur}); _toast('📢 Duyuru yayınlandı');
  }
  async function clearBroadcast() {
    await _upd('broadcast/current',{active:false}); _toast('🚫 Duyuru kaldırıldı');
  }

  async function sendSegmentNotif() {
    const segment=document.getElementById('bc_segment')?.value, text=document.getElementById('bc_seg_text')?.value?.trim();
    if(!text) return _toast('Bildirim metni boş','error');
    const users=await _get('users')||{}; const now=Date.now(); const DAY=86400000;
    const targets=Object.keys(users).filter(id=>{
      const u=users[id];
      if(segment==='vip') return u.isVip;
      if(segment==='lv10plus') return (u.level||1)>=10;
      if(segment==='lv25plus') return (u.level||1)>=25;
      if(segment==='lv50plus') return (u.level||1)>=50;
      if(segment==='inactive') return !u.lastLogin||(now-u.lastLogin)>14*DAY;
      if(segment==='new') return u.createdAt&&(now-u.createdAt)<7*DAY;
      return true;
    });
    const batch={};
    targets.forEach(id=>{const key=db().ref().push().key;batch['notifs/'+id+'/'+key]={type:'admin_notif',icon:'📢',msg:text,ts:TS(),read:false};});
    await db().ref().update(batch);
    await _log('segment_notif',{segment,count:targets.length}); _toast(`📨 ${targets.length} kullanıcıya bildirim gönderildi`);
  }

  async function openBulkNotifModal() {
    _modal('📨 Toplu Bildirim', `
      <div style="padding:4px">
        <textarea id="bulk_msg" placeholder="Mesaj..." rows="3"
          style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px;resize:vertical;font-family:inherit;margin-bottom:8px"></textarea>
        <input type="text" id="bulk_icon" placeholder="İkon emoji" value="📢"
          style="width:100%;box-sizing:border-box;background:#060c18;border:1px solid #1a2f4a;color:#e2e8f0;border-radius:6px;padding:8px;font-size:12px;margin-bottom:8px">
        <button onclick="window.AP.sendBulkNotif()" style="${_btnStyle('blue')};width:100%">📨 Herkese Gönder</button>
      </div>`, true);
  }
  async function sendBulkNotif() {
    const msg=document.getElementById('bulk_msg')?.value?.trim(), icon=document.getElementById('bulk_icon')?.value||'📢';
    if(!msg) return _toast('Mesaj gir','error');
    await _notifyAll(msg,icon); await _log('bulk_notif',{msg:msg.slice(0,100)}); _toast('📨 Toplu bildirim gönderildi'); _closeModal();
  }

