  ticari: {label:'🏪 Ticari', maxAmount:5000000,baseRate:0.22,minScore:55},
  konut:  {label:'🏠 Konut',  maxAmount:20000000,baseRate:0.18,minScore:60},
  ihracat:{label:'🚢 İhracat',maxAmount:10000000,baseRate:0.15,minScore:65},
