/* ============================================================
   Skill ve zeka oyunları için handlers — ayrı dosyada/parçada
   ============================================================ */
window._GAME_HANDLERS = HANDLERS;
window._GAMES = GAMES;
window._gameMult = gameMult;
window._bonus = bonus;
window._canPlay = canPlay;
