  // Ürün görseli getir — ürün adına göre en iyi eşleşme
  window.GZ_getUrunGorsel = function (urunKey, urunName) {
    const key = (urunKey || '').toLowerCase();
    const name = (urunName || '').toLowerCase();
    const catalog = window.GZ_URUN_GORSELLER;

    // Direkt eşleşme
    if (catalog[key]) return catalog[key];

    // İsimde anahtar kelime ara
    for (const [k, v] of Object.entries(catalog)) {
      if (name.includes(k) || k.includes(name.split(' ')[0])) return v;
    }

    // Kategori rengi üret (ürün adından hash ile)
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#14b8a6'];
    const hash = name.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
    return { emoji: '📦', color: colors[hash % colors.length], bg: '#f9fafb', img: null };
  };

  /* ══════════════════════════════════════════════════════════════
     3. WEB AUDIO SES SİSTEMİ
     ══════════════════════════════════════════════════════════════ */

  let _audioCtx = null;
  function getAudioCtx() {
    if (!_audioCtx) {
      try { _audioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch (e) {}
    }
    return _audioCtx;
  }

  function playTone(type, opts) {
    const ctx = getAudioCtx();
    if (!ctx) return;

    // Kullanıcı etkileşimi gerekebilir
    if (ctx.state === 'suspended') ctx.resume().catch(() => {});

    const now = ctx.currentTime;
    const gain = ctx.createGain();
    gain.connect(ctx.destination);

    function note(freq, start, dur, vol) {
      const osc = ctx.createOscillator();
      const g = ctx.createGain();
      osc.connect(g);
      g.connect(gain);
      osc.frequency.value = freq;
      osc.type = opts?.wave || 'sine';
      g.gain.setValueAtTime(0, now + start);
      g.gain.linearRampToValueAtTime(vol || 0.3, now + start + 0.01);
      g.gain.exponentialRampToValueAtTime(0.001, now + start + dur);
      osc.start(now + start);
      osc.stop(now + start + dur + 0.05);
    }

    switch (type) {
      case 'notify':    // Kısa ding — bildirim
        note(880, 0,    0.15, 0.25);
        note(1100, 0.15, 0.2, 0.2);
        break;
      case 'sale':      // Para sesi — satış
        note(523, 0,    0.08, 0.3);
        note(659, 0.08, 0.08, 0.3);
        note(784, 0.16, 0.08, 0.3);
        note(1047,0.24, 0.2,  0.25);
        break;
      case 'level':     // Fanfare — level atla
        note(523, 0,    0.1, 0.35);
        note(659, 0.1,  0.1, 0.35);
        note(784, 0.2,  0.1, 0.35);
        note(1047,0.3,  0.25,0.35);
        note(1319,0.55, 0.4, 0.3);
        break;
      case 'error':     // Hata — kısa boing
        note(220, 0,    0.15, 0.3);
        note(196, 0.1,  0.2,  0.25);
        break;
      case 'reward':    // Ödül — jingle
        note(784, 0,    0.1, 0.3);
        note(988, 0.1,  0.1, 0.3);
        note(1175,0.2,  0.1, 0.3);
        note(1568,0.3,  0.3, 0.3);
        break;
      case 'click':     // Hafif tık
        note(600, 0,    0.05, 0.15);
        break;
      case 'news':      // Haber geldi
        note(440, 0,    0.1, 0.2);
        note(550, 0.12, 0.12,0.2);
        note(660, 0.24, 0.15,0.15);
        break;
      case 'buy':       // Satın alma
        note(392, 0,    0.08, 0.25);
        note(523, 0.08, 0.12, 0.25);
        note(659, 0.2,  0.18, 0.2);
        break;
    }
  }

  // Global erişim
  window.GZ_SOUND = {
    play:    playTone,
    notify:  () => playTone('notify'),
    sale:    () => playTone('sale'),
    level:   () => playTone('level'),
    error:   () => playTone('error'),
    reward:  () => playTone('reward'),
    click:   () => playTone('click'),
    news:    () => playTone('news'),
    buy:     () => playTone('buy'),
  };

  // Toast'a ses entegre et
  const _origToast = window.toast;
  window.toast = function (msg, kind, dur) {
    if (typeof _origToast === 'function') _origToast(msg, kind, dur);
    switch (kind) {
      case 'success': playTone('sale');   break;
      case 'error':   playTone('error');  break;
      case 'info':    playTone('notify'); break;
      case 'reward':  playTone('reward'); break;
    }
  };

