  // Haber kartlarını yeniden render et — gelişmiş görselli
  function patchNewsRendering() {
    injectNewsStyles();

    // hz-body'e filtre satırı ve hero banner ekle
    const body = document.getElementById('haberlerOverlay');
    if (!body) return;

    const hzBody = body.querySelector('.hz-body');
    if (!hzBody || hzBody.dataset.patched) return;
    hzBody.dataset.patched = '1';

    // Hero Banner
    const heroBanner = document.createElement('div');
    heroBanner.className = 'hz-hero-banner';
    heroBanner.innerHTML = `
      <img src="https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&q=80" loading="lazy" onerror="this.style.display='none'"/>
      <div class="hz-hero-text">
        <div class="hz-hero-title">📰 GameZone<br>Haber Merkezi</div>
        <div class="hz-hero-sub">AI destekli canlı haber akışı · Her 15 dakikada güncellenir</div>
      </div>`;
    hzBody.insertBefore(heroBanner, hzBody.firstChild);

    // Filtre Satırı
    const filterRow = document.createElement('div');
    filterRow.className = 'hz-filter-row';
    filterRow.id = 'hzFilterRow';
    filterRow.innerHTML = `
      <button class="hz-filter-btn active" data-filter="all" onclick="hzSetFilter(this,'all')">🌐 Tümü</button>
      <button class="hz-filter-btn" data-filter="haber"    onclick="hzSetFilter(this,'haber')">📰 Haber</button>
      <button class="hz-filter-btn" data-filter="guncell"  onclick="hzSetFilter(this,'guncell')">🔄 Güncelleme</button>
      <button class="hz-filter-btn" data-filter="etkinlik" onclick="hzSetFilter(this,'etkinlik')">🎉 Etkinlik</button>
      <button class="hz-filter-btn" data-filter="ozel"     onclick="hzSetFilter(this,'ozel')">⭐ Özel</button>`;
    hzBody.insertBefore(filterRow, hzBody.children[1]);
  }

  window.hzSetFilter = function (btn, filter) {
    document.querySelectorAll('.hz-filter-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    const cards = document.querySelectorAll('.hz-card');
    cards.forEach(c => {
      const tag = c.dataset.tag || '';
      c.style.display = (filter === 'all' || tag === filter) ? 'block' : 'none';
    });
  };

  // renderCard fonksiyonunu override et — görselli, gelişmiş kart
  function patchRenderCard() {
    if (window._hzRenderCardPatched) return;
    window._hzRenderCardPatched = true;

    // 300ms bekle, orijinal fonksiyon yüklensin
    setTimeout(function () {
      // hzFeed'i observe et, yeni kartlar eklenince tag data'sı ekle
      const feed = document.getElementById('hzFeed');
      if (!feed) return;

      const obs = new MutationObserver(function () {
        feed.querySelectorAll('.hz-card:not([data-patched])').forEach(card => {
          card.dataset.patched = '1';

          // Tag sınıfı ekle
          const tagEl = card.querySelector('.hz-tag');
          if (tagEl) {
            if (tagEl.classList.contains('hz-tag-haber'))    { card.classList.add('hz-card-haber');    card.dataset.tag = 'haber'; }
            if (tagEl.classList.contains('hz-tag-guncell'))  { card.classList.add('hz-card-guncell');  card.dataset.tag = 'guncell'; }
            if (tagEl.classList.contains('hz-tag-ozel'))     { card.classList.add('hz-card-ozel');     card.dataset.tag = 'ozel'; }
            if (tagEl.classList.contains('hz-tag-etkinlik')) { card.classList.add('hz-card-etkinlik'); card.dataset.tag = 'etkinlik'; }
          }

          // Resim wrapper'ı iyileştir
          const img = card.querySelector('.hz-img');
          if (img && !img.parentElement.classList.contains('hz-img-wrapper')) {
            const wrapper = document.createElement('div');
            wrapper.className = 'hz-img-wrapper';
            img.parentNode.insertBefore(wrapper, img);
            wrapper.appendChild(img);

            // Overlay ekle
            const overlay = document.createElement('div');
            overlay.className = 'hz-img-overlay';
            wrapper.appendChild(overlay);

            // Tag badge
            const badge = document.createElement('div');
            badge.className = 'hz-img-badge';
            const tag = card.dataset.tag || 'haber';
            const labels = { haber: '📰 HABER', guncell: '🔄 GÜNCELLEME', ozel: '⭐ ÖZEL', etkinlik: '🎉 ETKİNLİK' };
            badge.textContent = labels[tag] || '📰';
            wrapper.appendChild(badge);
          }

          // Resim URL yoksa veya random Unsplash'sa, curated resim ata
          if (img) {
            const tag = card.dataset.tag || 'haber';
            const postId = card.id.replace('hzp-', '');
            const curatedUrl = window.GZ_getNewsImage(tag, postId);
            if (!img.src || img.src.includes('source.unsplash.com') || img.naturalWidth === 0) {
              img.src = curatedUrl;
            }
            img.onerror = function () {
              this.src = curatedUrl;
            };
          }
        });
      });
      obs.observe(feed, { childList: true, subtree: true });
    }, 500);
  }

