// bankRepay yoksa fallback
window.bankRepay = window.bankRepay || async function(amount) {
  const uid = window.GZ?.uid;
  const ok = await window.spendCash(uid, amount, 'kredi-odeme');
  if (!ok) { window.toast?.('Yetersiz bakiye', 'error'); return false; }
  await window.db.ref(`bank/${uid}/loan`).transaction(cur => Math.max(0, (cur || 0) - amount));
  window.toast?.(`✅ ${window.cashFmt(amount)} ödendi`, 'success');
  return true;
};

