window.renderCuzdan = async function() {
  const main = document.getElementById('appMain');
  if (!main) return;
  main.innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner" style="margin:0 auto"></div></div>';

  const uid = window.GZ?.uid;
  const userData = await window.dbGet(`users/${uid}`) || {};
  const money = userData.money || 0;
  const diamonds = userData.diamonds || 0;
  const txLog = await window.dbGet(`txLog/${uid}`) || {};
  const txList = Object.values(txLog).sort((a, b) => b.ts - a.ts).slice(0, 20);

  main.innerHTML = `
    <div class="page-title">👛 Dijital Cüzdan</div>
    <div class="stats-grid">
      <div class="stat-box"><div class="lbl">💰 Bakiye</div><div class="val green">${window.cashFmt(money)}</div></div>
      <div class="stat-box"><div class="lbl">💎 Elmas</div><div class="val" style="color:#60a5fa">${window.fmtInt(diamonds)}</div></div>
    </div>
    <div class="card mt-12">
      <div class="card-title">💸 Para Transferi</div>
      <div class="input-group">
        <label>Hedef Kullanıcı ID</label>
        <input type="text" id="cuzdanTarget" placeholder="Kullanıcı UID">
      </div>
      <div class="input-group">
        <label>Tutar (₺)</label>
        <input type="number" id="cuzdanAmount" placeholder="₺" min="1">
      </div>
      <button class="btn-primary" onclick="cuzdanTransfer()">💸 Gönder</button>
    </div>
    <div class="section-title mt-16">📜 Son İşlemler</div>
    ${txList.length === 0
      ? window.emptyState('📜', 'İşlem yok', 'Henüz işlem yapmadınız')
      : txList.map(tx => `
        <div class="card" style="padding:10px 14px;margin-bottom:6px">
          <div style="display:flex;justify-content:space-between;align-items:center">
            <div>
              <div style="font-size:13px;font-weight:600">${tx.type || 'İşlem'}</div>
              <div style="font-size:11px;color:var(--text-muted)">${new Date(tx.ts || 0).toLocaleString('tr-TR')}</div>
            </div>
            <div style="font-weight:700;color:${(tx.amount || 0) >= 0 ? '#22c55e' : '#ef4444'}">
              ${(tx.amount || 0) >= 0 ? '+' : ''}${window.cashFmt(Math.abs(tx.amount || 0))}
            </div>
          </div>
        </div>
      `).join('')}
  `;
};

window.cuzdanTransfer = async function() {
  const uid = window.GZ?.uid;
  const targetUid = document.getElementById('cuzdanTarget')?.value?.trim();
  const amount = parseInt(document.getElementById('cuzdanAmount')?.value) || 0;

  if (!targetUid || targetUid === uid) return window.toast?.('Geçersiz hedef', 'error');
  if (amount <= 0) return window.toast?.('Geçerli tutar gir', 'error');

  const targetUser = await window.dbGet(`users/${targetUid}`);
  if (!targetUser) return window.toast?.('Kullanıcı bulunamadı', 'error');

  const commission = Math.max(5, Math.floor(amount * 0.001));
  const total = amount + commission;

  const ok = await window.spendCash(uid, total, `transfer-to-${targetUid.slice(0, 8)}`);
  if (!ok) return window.toast?.('Yetersiz bakiye', 'error');

  await window.addCash(targetUid, amount, `transfer-from-${uid.slice(0, 8)}`);
  await window.dbPush(`txLog/${uid}`, { type: 'transfer_gonder', amount: -total, hedef: targetUid.slice(0, 8), ts: Date.now() });
  await window.dbPush(`txLog/${targetUid}`, { type: 'transfer_al', amount, gonderen: uid.slice(0, 8), ts: Date.now() });

  window.toast?.(`✅ ${window.cashFmt(amount)} gönderildi. Komisyon: ${window.cashFmt(commission)}`, 'success');
  window.renderCuzdan();
};

