window.karaborsaSatinAl = async function(k) {
  const uid = window.GZ?.uid;
  const l = await window.dbGet(`karaborsa/listings/${k}`);
  if (!l || l.sold) return window.toast?.('Bu ilan artık geçersiz', 'error');
  const ok = await window.spendCash(uid, l.price, `karaborsa-${l.item}`);
  if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
  await window.dbUpdate(`karaborsa/listings/${k}`, { sold: true, buyerId: uid, soldAt: Date.now() });
  if (l.sellerId) await window.addCash(l.sellerId, Math.floor(l.price * 0.95), `karaborsa-satis`);
  window.toast?.(`✅ ${l.item} satın alındı`, 'success');
  window.renderKaraborsa();
};

