window.buyRobot = window.buyRobot || async function(rid) {
  const uid = window.GZ?.uid;
  const r = window.ROBOT_PAKETLERI?.find(x => x.id === rid);
  if (!r) return window.toast?.('Robot bulunamadı', 'error');
  const dia = window.GZ.data?.diamonds || 0;
  if (dia < r.diamonds) return window.toast?.(`Yetersiz elmas (gereken: ${r.diamonds} 💎)`, 'error');
  await window.db.ref(`users/${uid}/diamonds`).transaction(cur => (cur || 0) - r.diamonds);
  const robotUntil = Math.max(Date.now(), (window.GZ.data?.robotUntil || 0)) + r.hours * 3600000;
  await window.dbUpdate(`users/${uid}`, { robotUntil });
  if (window.GZ?.data) { window.GZ.data.diamonds -= r.diamonds; window.GZ.data.robotUntil = robotUntil; }
  window.toast?.(`🤖 Robot ${r.hours} saat aktif edildi!`, 'success');
};

