// buyShelfStock yoksa fallback
window.buyShelfStock = window.buyShelfStock || async function(sid, itemKey, qty) {
  const uid = window.GZ?.uid;
  const u = window.URUNLER?.[itemKey];
  if (!u) return window.toast?.('Ürün bulunamadı', 'error');
  const total = qty * u.base;
  const ok = await window.spendCash(uid, total, `stok-${itemKey}`);
  if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
  await window.db.ref(`businesses/${uid}/shops/${sid}/shelves/${itemKey}/stock`).transaction(cur => (cur || 0) + qty);
  window.toast?.(`✅ ${qty} ${u.unit || 'adet'} ${u.name} alındı`, 'success');
};

// Dükkan pazar satış döngüsü — her 90 saniyede bir çalışır
(function shopSalesCycle() {
  const _w = setInterval(function() {
    if (!window.GZ?.uid || !window.db) return;
    clearInterval(_w);

    async function runSales() {
      const uid = window.GZ?.uid;
      if (!uid) return;

      const shops = await window.dbGet(`businesses/${uid}/shops`);
      if (!shops) return;

      let totalRevenue = 0;
      const updates = {};

      for (const sid of Object.keys(shops)) {
        const s = shops[sid];
        if (!s || !s.shelves) continue;

        for (const [itemKey, shelf] of Object.entries(s.shelves)) {
          if (!shelf || (shelf.stock || 0) <= 0) continue;
          const u = window.URUNLER?.[itemKey];
          if (!u) continue;

          // Satış miktarı hesapla (fiyata göre değişir)
          const price = shelf.price || u.base;
          const priceRatio = price / u.base;
          const demand = Math.max(1, Math.round(10 / priceRatio));
          const sold = Math.min(shelf.stock || 0, demand);
          if (sold <= 0) continue;

          const revenue = sold * price;
          totalRevenue += revenue;

          updates[`businesses/${uid}/shops/${sid}/shelves/${itemKey}/stock`] = Math.max(0, (shelf.stock || 0) - sold);
          updates[`businesses/${uid}/shops/${sid}/shelves/${itemKey}/totalSold`] = (shelf.totalSold || 0) + sold;
          updates[`businesses/${uid}/shops/${sid}/shelves/${itemKey}/totalRevenue`] = (shelf.totalRevenue || 0) + revenue;
        }
      }

      if (totalRevenue > 0) {
        await window.addCash(uid, totalRevenue, 'dukkan-satis');
        await window.db.ref().update(updates);
        // Topbar güncelle
        if (typeof window.updateTopbar === 'function') window.updateTopbar();
      }
    }

    // Her 90 saniyede bir çalıştır
    setInterval(runSales, 90000);
    // 15 saniye sonra ilk çalıştır
    setTimeout(runSales, 15000);

  }, 800);
})();

