// modalNewShop override: aynı türden 2. dükkan açılamaz, kilitli olanları göster
(function patchModalNewShop() {
  const _orig = window.modalNewShop;
  window.modalNewShop = async function() {
    const lv = window.GZ?.data?.level || 1;
    const myShops = await (window.dbGet?.(`businesses/${window.GZ?.uid}/shops`)) || {};
    const ownedTypes = new Set(Object.values(myShops).map(s => s.type));

    if (window.SHOP_CATALOG) {
      let html = `<p style="font-size:12px;color:var(--text-muted);margin-bottom:12px">
        Her türden <b>sadece 1 dükkan</b> açılabilir. ✅ = sahipsin, 🔒 = seviye gerekli.
      </p><div class="shop-builder-grid">`;

      Object.entries(window.SHOP_CATALOG).forEach(([type, def]) => {
        const locked  = lv < def.lv;
        const owned   = ownedTypes.has(type);
        const cats    = (def.cats || []).map(c => (window.URUN_KATEGORI_TUM?.[c]) || c).join(' · ');
        const btnHtml = owned
          ? `<button class="btn-secondary" disabled style="background:#22c55e22;color:#22c55e">✅ Açık</button>`
          : locked
          ? `<button class="btn-secondary" disabled>🔒 Lv ${def.lv}</button>`
          : `<button class="btn-primary" onclick="pickCity('${type}')">Aç — ${window.cashFmt?.(def.cost)||def.cost+'₺'}</button>`;

        html += `<div class="shop-build-card ${owned?'owned':locked?'locked':''}">
          <div class="sbc-icon">${def.icon}</div>
          <div class="sbc-name">${def.name}</div>
          <div class="sbc-cats" style="font-size:10px;color:var(--text-muted)">${cats}</div>
          <div class="sbc-meta"><span>Lv ${def.lv}</span><span class="${owned?'green':''}">
            ${owned ? 'Sahipsin' : window.cashFmt?.(def.cost)||def.cost+'₺'}
          </span></div>
          ${btnHtml}
        </div>`;
      });
      html += '</div>';
      window.showModal?.('🏪 Yeni Dükkan Aç', html);
      return;
    }
    if (_orig) _orig();
  };
})();

/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 29 — GELİŞMİŞ VERGİ DAİRESİ
   ══════════════════════════════════════════════════════════════════════════════ */

window.renderVergiOyuncu = async function() {
  const main = document.getElementById('appMain');
  main.innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner" style="margin:0 auto"></div></div>';

  const uid  = window.GZ?.uid;
  const lv   = window.GZ?.data?.level || 1;
  const accountAge = Date.now() - (window.GZ?.data?.createdAt || Date.now());
  const isNewPlayer = accountAge < 7*24*3600*1000 || lv < 5;
  const discount = isNewPlayer ? 0.20 : 1.0;
  const taxMult  = Math.max(0.1, Math.min(1.0, lv / 20));

  const [shops, gardens, farms, factories, mines, bank, mbRates, dbFaizler] = await Promise.all([
    window.dbGet?.(`businesses/${uid}/shops`)       .catch?.(()=>({})) || {},
    window.dbGet?.(`businesses/${uid}/gardens`)     .catch?.(()=>({})) || {},
    window.dbGet?.(`businesses/${uid}/farms`)       .catch?.(()=>({})) || {},
    window.dbGet?.(`businesses/${uid}/factories`)   .catch?.(()=>({})) || {},
    window.dbGet?.(`businesses/${uid}/mines`)       .catch?.(()=>({})) || {},
    window.dbGet?.(`bank/${uid}`)                   .catch?.(()=>({})) || {},
    window.dbGet?.('system/merkezBankasi')          .catch?.(()=>({})) || {},
    window.dbGet?.('system/bankFaizler')            .catch?.(()=>({})) || {},
  ]);

  const nShops   = Object.keys(shops||{}).length;
  const nGardens = Object.keys(gardens||{}).length;
  const nFarms   = Object.keys(farms||{}).length;
  const nFacts   = Object.keys(factories||{}).length;
  const nMines   = Object.keys(mines||{}).length;
  const nBiz     = nShops+nGardens+nFarms+nFacts+nMines;

  const shopTax    = nShops   * ((mbRates?.rates_shopTax||500)*taxMult*discount);
  const gardenTax  = nGardens * ((mbRates?.rates_gardenTax||300)*taxMult*discount);
  const farmTax    = nFarms   * ((mbRates?.rates_farmTax||300)*taxMult*discount);
  const factoryTax = nFacts   * ((mbRates?.rates_factoryTax||800)*taxMult*discount);
  const mineTax    = nMines   * ((mbRates?.rates_mineTax||600)*taxMult*discount);
  const gelirOrani = ((mbRates?.gelirOrani)||8)/100;
  const haftalikGelir = window.GZ?.data?.weeklyRevenue || 0;
  const gelirVer   = +(haftalikGelir * gelirOrani).toFixed(2);
  const toplamVergi= shopTax+gardenTax+farmTax+factoryTax+mineTax+gelirVer;

  const loan    = bank?.loan || 0;
  const loanBankId = bank?.loanBankId || 'ziraat';
  const faiz    = dbFaizler?.[loanBankId] || 0.032;
  const weeklyFaiz = loan > 0 ? +(loan * faiz / 52).toFixed(2) : 0;
  const expPerBiz  = lv<=10?200:lv<=25?500:1000;
  const expense    = nBiz * expPerBiz * discount;

  const cf = window.cashFmt || (n => n.toLocaleString('tr-TR')+'₺');
  const row = (label, val, sub='') => val > 0 ? `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid var(--border,#e5e7eb22)">
      <div><div style="font-size:13px">${label}</div>${sub?`<div style="font-size:10px;color:var(--text-muted)">${sub}</div>`:''}</div>
      <b style="color:#f59e0b;font-size:14px">${cf(val)}</b>
    </div>` : '';

  const nextSatMs = (() => {
    const d=new Date(); d.setDate(d.getDate()+(7-d.getDay()+6)%7||7); d.setHours(0,0,0,0); return d.getTime();
  })();
  const diffMs  = nextSatMs - Date.now();
  const diffH   = Math.floor(diffMs/3600000);
  const diffM   = Math.floor((diffMs%3600000)/60000);

  main.innerHTML = `
    <div class="page-title">🏛️ Vergi Dairesi</div>

    ${isNewPlayer ? `<div class="card" style="background:linear-gradient(135deg,#166534,#14532d);border:1px solid #22c55e;margin-bottom:12px">
      <div style="display:flex;align-items:center;gap:10px">
        <span style="font-size:24px">✨</span>
        <div>
          <div style="font-weight:700;color:#22c55e">Yeni Oyuncu Vergi İndirimi Aktif!</div>
          <div style="font-size:12px;color:#86efac">Tüm vergi ve giderler %80 indirimli hesaplanıyor. Lv 5 sonrası normal orana döner.</div>
        </div>
      </div>
    </div>` : ''}

    <div class="card" style="background:#1c1917;border:1px solid #78350f;margin-bottom:12px">
      <div style="font-weight:700;font-size:14px;color:#fbbf24;margin-bottom:12px">📅 Sonraki Tahsil: ${diffH}s ${diffM}dk sonra (Cumartesi)</div>
      ${row('🏪 Dükkan Vergisi × '+nShops, shopTax, `${nShops} dükkan × ${cf((mbRates?.rates_shopTax||500)*taxMult*discount)}`)}
      ${row('🌱 Bahçe Vergisi × '+nGardens, gardenTax)}
      ${row('🐄 Çiftlik Vergisi × '+nFarms, farmTax)}
      ${row('🏭 Fabrika Vergisi × '+nFacts, factoryTax)}
      ${row('⛏️ Maden Vergisi × '+nMines, mineTax)}
      ${row('💰 Gelir Vergisi', gelirVer, `Bu haftaki gelir: ${cf(haftalikGelir)} × %${(gelirOrani*100).toFixed(0)}`)}
      ${row('🏢 İşletme Gideri', expense, `${nBiz} işletme × ${cf(expPerBiz)}/hafta`)}
      ${row('💳 Kredi Faizi (Haftalık)', weeklyFaiz, loan > 0 ? `${cf(loan)} borç × %${(faiz*100).toFixed(2)}/yıl ÷ 52` : '')}
      <div style="display:flex;justify-content:space-between;align-items:center;padding:12px 0;margin-top:4px">
        <b style="font-size:15px">TOPLAM HAFTALIK</b>
        <b style="font-size:18px;color:#f59e0b">${cf(toplamVergi+expense+weeklyFaiz)}</b>
      </div>
    </div>

    <div class="card" style="margin-bottom:12px">
      <div style="font-weight:700;margin-bottom:12px">📊 Beyanname Geçmişi</div>
      <div id="vergiGecmis"><div class="spinner" style="margin:10px auto"></div></div>
    </div>

    <div class="card" style="background:#0c1a2e;border:1px solid #1e3a5f;margin-bottom:12px">
      <div style="font-weight:700;color:#60a5fa;margin-bottom:8px">ℹ️ Vergi Bilgisi</div>
      <div style="font-size:12px;color:#94a3b8;line-height:1.8">
        • Vergiler her <b>Cumartesi</b> otomatik tahsil edilir<br>
        • Lv 1-10: Vergi tabanının <b>%5-50'si</b>, Lv 20+: tam oran<br>
        • Gelir vergisi, o hafta kazandığın paranın %${(gelirOrani*100).toFixed(0)}'idir<br>
        • Ödeme yapılamazsa borca dönüşür (kredi notu -3)<br>
        • Borç ödedikçe kredi notun yükselir
      </div>
    </div>`;

  // Vergi geçmişini yükle
  window.dbGet?.(`system/merkezBankasi/vergiLog`).then(log => {
    const el = document.getElementById('vergiGecmis');
    if (!el) return;
    if (!log) { el.innerHTML = '<p style="color:var(--text-muted);font-size:12px">Henüz kayıt yok</p>'; return; }
    const myLogs = Object.values(log).filter(l => l.uid === uid).slice(-10).reverse();
    if (!myLogs.length) { el.innerHTML = '<p style="color:var(--text-muted);font-size:12px">Kayıt bulunamadı</p>'; return; }
    el.innerHTML = myLogs.map(l => {
      const d = new Date(l.ts || 0);
      return `<div style="display:flex;justify-content:space-between;font-size:12px;padding:6px 0;border-bottom:1px solid var(--border,#e5e7eb11)">
        <span>${d.toLocaleDateString('tr-TR')}</span>
        <span style="color:#f59e0b">${cf(l.vergi||0)} vergi</span>
        <span style="color:#3b82f6">${cf(l.faiz||0)} faiz</span>
      </div>`;
    }).join('');
  }).catch(()=>{});
};

/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 30 — GELİŞMİŞ BORÇ YAPILANDIRMA (KONKORDATO)
   ══════════════════════════════════════════════════════════════════════════════ */

window.renderKonkurato = async function() {
  const main = document.getElementById('appMain');
  main.innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner" style="margin:0 auto"></div></div>';

  const uid   = window.GZ?.uid;
  const bank  = await window.dbGet?.(`bank/${uid}`).catch(()=>({})) || {};
  const borc  = bank.loan || 0;
  const krediNotu = typeof window.getKrediNotu === 'function' ? await window.getKrediNotu(uid) : 50;
  const basvurular= await window.dbGet?.(`konkurato/${uid}`).catch(()=>({})) || {};
  const cf = window.cashFmt || (n => n.toLocaleString('tr-TR')+'₺');

  // Taksit planları
  const planlar = [
    { id: 'p3',  label: '3 Aylık',  ay:3,  indirim:0,    faiz:0.02 },
    { id: 'p6',  label: '6 Aylık',  ay:6,  indirim:0.05, faiz:0.015 },
    { id: 'p12', label: '12 Aylık', ay:12, indirim:0.10, faiz:0.01 },
    { id: 'p24', label: '24 Aylık', ay:24, indirim:0.20, faiz:0.008, minBorc: 50000 },
  ];

  const mevcut = basvurular?.aktif;

  main.innerHTML = `
    <div class="page-title">📋 Borç Yapılandırma</div>

    <div class="card" style="background:linear-gradient(135deg,#1c1917,#0c0a09);border:1px solid #78350f;margin-bottom:12px">
      <div style="display:flex;justify-content:space-between;margin-bottom:16px">
        <div>
          <div style="font-size:11px;color:#94a3b8">TOPLAM BORCUN</div>
          <div style="font-size:36px;font-weight:900;color:${borc>0?'#ef4444':'#22c55e'}">${cf(borc)}</div>
        </div>
        <div style="text-align:right">
          <div style="font-size:11px;color:#94a3b8">KREDİ NOTUN</div>
          <div style="font-size:36px;font-weight:900;color:${krediNotu>=80?'#22c55e':krediNotu>=60?'#f59e0b':'#ef4444'}">${krediNotu}</div>
        </div>
      </div>
      ${borc > 0 ? `<div style="font-size:12px;color:#94a3b8;background:#1c1917;border-radius:8px;padding:10px">
        Haftalık faiz yükü: <b style="color:#f59e0b">${cf(+(borc*0.032/52).toFixed(2))}</b> / hafta
      </div>` : `<div style="color:#22c55e;font-size:13px">✅ Borcun bulunmuyor, harika!</div>`}
    </div>

    ${mevcut ? `
    <div class="card" style="background:#0f2e1c;border:1px solid #22c55e;margin-bottom:12px">
      <div style="font-weight:700;color:#22c55e;margin-bottom:10px">✅ Aktif Yapılandırma Planı</div>
      <div style="font-size:13px;line-height:2">
        <div>Plan: <b>${mevcut.label}</b></div>
        <div>Aylık taksit: <b>${cf(mevcut.taksit)}</b></div>
        <div>Kalan: <b>${cf(mevcut.kalan)}</b></div>
        <div>Sonraki ödeme: <b>${new Date(mevcut.nextDate||Date.now()).toLocaleDateString('tr-TR')}</b></div>
      </div>
      <button class="btn-primary" style="width:100%;margin-top:12px;background:#16a34a"
        onclick="window.konkuratoPay?.()">💸 Taksit Öde — ${cf(mevcut.taksit)}</button>
    </div>` : ''}

    ${borc > 0 && !mevcut ? `
    <div style="font-weight:700;font-size:13px;color:var(--text-muted);margin-bottom:12px">🗓️ Yapılandırma Planı Seç</div>
    ${planlar.map(p => {
      const indirimliBorc = +(borc * (1 - p.indirim)).toFixed(2);
      const taksit = +(indirimliBorc * (1 + p.faiz * p.ay) / p.ay).toFixed(2);
      const disabled = p.minBorc && borc < p.minBorc;
      return `<div class="card" style="margin-bottom:10px;border:1px solid ${disabled?'#374151':'#1e3a5f'};opacity:${disabled?'.5':'1'}">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">
          <div style="font-weight:700;font-size:15px">${p.label}</div>
          <div style="font-size:10px;color:var(--text-muted)">${p.indirim>0?`%${p.indirim*100} anapara indirimi`:''} Faiz: %${(p.faiz*100).toFixed(1)}/ay</div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px">
          <div style="background:#0f172a;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:10px;color:#64748b">ANAPARA</div>
            <div style="font-weight:700;font-size:12px">${cf(indirimliBorc)}</div>
          </div>
          <div style="background:#0f172a;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:10px;color:#64748b">AYLIK TAKSİT</div>
            <div style="font-weight:700;font-size:12px;color:#3b82f6">${cf(taksit)}</div>
          </div>
          <div style="background:#0f172a;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:10px;color:#64748b">TOPLAM</div>
            <div style="font-weight:700;font-size:12px;color:#f59e0b">${cf(taksit*p.ay)}</div>
          </div>
        </div>
        ${disabled
          ? `<div style="text-align:center;font-size:11px;color:#6b7280">Min ${cf(p.minBorc)} borç gerekli</div>`
          : `<button class="btn-primary" style="width:100%" onclick="window.konkuratoBasvur?.('${p.id}', ${taksit}, ${indirimliBorc})">
              📋 Bu Planı Seç
            </button>`
        }
      </div>`;
    }).join('')}` : ''}

    <div class="card" style="background:#0c1a2e;border:1px solid #1e3a5f">
      <div style="font-size:12px;color:#64748b;line-height:1.8">
        💡 <b>Yapılandırma Avantajları:</b><br>
        • Haftalık ceza kesilmez, faiz düşer<br>
        • 12+ aylık planlarda anapara indirimi<br>
        • Düzenli ödeme → kredi notu artar<br>
        • İflası önler, oyunda kalma garantisi
      </div>
    </div>`;

  window.konkuratoBasvur = async function(planId, taksit, kalan) {
    const plan = planlar.find(p => p.id === planId);
    if (!plan) return;
    const nextDate = Date.now() + 30*24*3600*1000;
    await window.dbSet?.(`konkurato/${uid}/aktif`, { label:plan.label, taksit, kalan, nextDate, planId, createdAt:Date.now() });
    window.toast?.('✅ Yapılandırma planı başlatıldı!', 'success');
    window.renderKonkurato?.();
  };

  window.konkuratoPay = async function() {
    const plan = (await window.dbGet?.(`konkurato/${uid}/aktif`)) || {};
    if (!plan.taksit) return;
    const ok = await window.spendCash?.(uid, plan.taksit, 'konkurato-taksit');
    if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
    const yeniKalan = Math.max(0, (plan.kalan||0) - plan.taksit);
    if (yeniKalan <= 0) {
      await window.dbSet?.(`konkurato/${uid}/aktif`, null);
      await window.dbUpdate?.(`bank/${uid}`, { loan: 0 });
      window.toast?.('🎉 Borç tamamen ödendi!', 'success');
    } else {
      const nextDate = Date.now() + 30*24*3600*1000;
      await window.dbUpdate?.(`konkurato/${uid}/aktif`, { kalan: yeniKalan, nextDate });
      await window.dbUpdate?.(`bank/${uid}`, { loan: yeniKalan });
      window.toast?.(`✅ Taksit ödendi! Kalan: ${window.cashFmt?.(yeniKalan)}`, 'success');
    }
    if (typeof window.updateKrediNotu === 'function') await window.updateKrediNotu(uid, 3, 'Taksit ödeme');
    window.renderKonkurato?.();
  };
};

/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 31 — GELİŞMİŞ KARA BORSA
   ══════════════════════════════════════════════════════════════════════════════ */

window.renderKaraborsa = async function() {
  const main = document.getElementById('appMain');
  const lv   = window.GZ?.data?.level || 1;
  if (lv < 15) {
    main.innerHTML = `<div class="page-title">🕶️ Kara Borsa</div>
      <div class="card" style="text-align:center;padding:40px">
        <div style="font-size:48px">🔒</div>
        <h3>Seviye 15 Gerekli</h3>
        <p>Mevcut: Lv ${lv} — ${15-lv} seviye daha gerekiyor.</p>
      </div>`;
    return;
  }

  const uid = window.GZ?.uid;
  const envanterim = await window.dbGet?.(`businesses/${uid}/mainWarehouse`).catch(()=>({})) || {};
  const karaBorsaLog = await window.dbGet?.(`karaborsa/${uid}/log`).catch(()=>({})) || {};
  const logArr = Object.values(karaBorsaLog).slice(-5).reverse();
  const cf = window.cashFmt || (n => n.toLocaleString('tr-TR')+'₺');

  const items = window.BLACKMARKET_ITEMS || [
    { code:'sigara',    name:'Kaçak Sigara',   emo:'🚬', priceMin:50,  priceMax:200,  risk:0.15, profit:3.5, cat:'temel' },
    { code:'altin_kc', name:'Kaçak Altın',     emo:'🥇', priceMin:500, priceMax:2000, risk:0.25, profit:2.8, cat:'maden' },
    { code:'ilaç',     name:'Sahte İlaç',      emo:'💊', priceMin:80,  priceMax:350,  risk:0.30, profit:4.0, cat:'eczane' },
    { code:'akaryakit',name:'Kaçak Akaryakıt', emo:'⛽', priceMin:30,  priceMax:120,  risk:0.20, profit:3.2, cat:'benzin' },
    { code:'elektronik',name:'Çalıntı El.',    emo:'📱', priceMin:300, priceMax:1500, risk:0.35, profit:4.5, cat:'elektronik' },
    { code:'silah',    name:'Yasak Silah',     emo:'🔫', priceMin:2000,priceMax:8000, risk:0.60, profit:6.0, cat:'silah' },
    { code:'kripto_kc',name:'Kara Kripto',     emo:'₿',  priceMin:200, priceMax:5000, risk:0.20, profit:2.5, cat:'kripto' },
  ];

  const riskRenk = r => r < 0.2 ? '#22c55e' : r < 0.4 ? '#f59e0b' : '#ef4444';
  const riskStar = r => {
    const n = Math.ceil(r * 5);
    return '⚠️'.repeat(n) + '⬜'.repeat(5-n);
  };

  main.innerHTML = `
    <div class="page-title">🕶️ Kara Borsa</div>
    <div class="card" style="background:linear-gradient(135deg,#0c0a09,#1c1917);border:1px solid #374151;margin-bottom:12px">
      <div style="display:flex;gap:12px;align-items:center">
        <span style="font-size:32px">⚠️</span>
        <div>
          <div style="font-weight:700;color:#f59e0b">Dikkat: Yüksek Risk Bölgesi</div>
          <div style="font-size:12px;color:#94a3b8">Yakalanırsan para cezası + kredi notu düşüşü. Risk oranı % ile gösterilir.</div>
        </div>
      </div>
    </div>

    <div style="display:grid;gap:10px;margin-bottom:16px">
    ${items.map(it => {
      const fiyat = Math.floor(it.priceMin + Math.random() * (it.priceMax - it.priceMin));
      const stok  = Math.floor(Math.random() * 500) + 50;
      return `<div class="card" style="border-left:3px solid ${riskRenk(it.risk)}">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
          <span style="font-size:28px">${it.emo}</span>
          <div style="flex:1">
            <div style="font-weight:700">${it.name}</div>
            <div style="font-size:11px;color:#64748b">Stok: ${stok} adet • Kâr: ×${it.profit}</div>
          </div>
          <div style="text-align:right">
            <div style="font-size:18px;font-weight:700;color:#f59e0b">${cf(fiyat)}</div>
            <div style="font-size:10px;color:${riskRenk(it.risk)}">Risk: ${riskStar(it.risk)}</div>
          </div>
        </div>
        <div style="display:flex;gap:8px">
          <input type="number" id="bm_${it.code}" placeholder="Adet" min="1" max="${stok}"
            style="flex:1;padding:8px;border-radius:8px;border:1px solid var(--border,#374151);background:var(--card-bg,#1c1917);color:var(--text,#fff);font-size:13px">
          <button style="padding:8px 14px;background:#dc2626;border:none;border-radius:8px;color:#fff;font-weight:700;cursor:pointer;font-size:12px"
            onclick="window.bmAl?.('${it.code}', ${fiyat}, ${it.risk})">AL</button>
          <button style="padding:8px 14px;background:#16a34a;border:none;border-radius:8px;color:#fff;font-weight:700;cursor:pointer;font-size:12px"
            onclick="window.bmSat?.('${it.code}', ${Math.floor(fiyat*it.profit*0.7)}, ${it.risk})">SAT</button>
        </div>
      </div>`;
    }).join('')}
    </div>

    ${logArr.length ? `
    <div class="card" style="margin-bottom:12px">
      <div style="font-weight:700;margin-bottom:10px">📜 Son İşlemler</div>
      ${logArr.map(l => `<div style="display:flex;justify-content:space-between;font-size:12px;padding:5px 0;border-bottom:1px solid var(--border,#374151)11">
        <span>${l.type==='buy'?'🛒 AL':'💰 SAT'} ${l.code}</span>
        <span style="color:${l.caught?'#ef4444':l.type==='sell'?'#22c55e':'#3b82f6'}">${l.caught?'❌ YAKALANDI':cf(l.amount)}</span>
        <span style="color:#64748b;font-size:10px">${new Date(l.ts||0).toLocaleTimeString('tr-TR')}</span>
      </div>`).join('')}
    </div>` : ''}`;

  window.bmAl = async function(code, fiyat, risk) {
    const q = parseInt(document.getElementById('bm_'+code)?.value) || 0;
    if (!q) return window.toast?.('Adet gir', 'error');
    const uid = window.GZ?.uid;
    const caught = Math.random() < risk;
    const totalCost = fiyat * q;
    if (caught) {
      const ceza = Math.floor(totalCost * 0.5);
      await window.spendCash?.(uid, ceza, 'karaborsa-ceza');
      if (typeof window.updateKrediNotu === 'function') await window.updateKrediNotu(uid, -10, 'Kara borsa');
      await window.dbPush?.(`karaborsa/${uid}/log`, { type:'buy', code, caught:true, ts:Date.now() });
      window.toast?.(`🚔 YAKALANDING! ${window.cashFmt?.(ceza)} ceza + kredi notu -10`, 'error');
    } else {
      const ok = await window.spendCash?.(uid, totalCost, 'karaborsa-al');
      if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
      const curStock = await window.dbGet?.(`businesses/${uid}/mainWarehouse/${code}_kb`) || 0;
      await window.dbSet?.(`businesses/${uid}/mainWarehouse/${code}_kb`, curStock + q);
      await window.dbPush?.(`karaborsa/${uid}/log`, { type:'buy', code, amount:totalCost, qty:q, ts:Date.now() });
      window.toast?.(`✅ ${q} adet alındı (gizli envanterde)`, 'success');
    }
    window.renderKaraborsa?.();
  };

  window.bmSat = async function(code, satFiyat, risk) {
    const q = parseInt(document.getElementById('bm_'+code)?.value) || 0;
    if (!q) return window.toast?.('Adet gir', 'error');
    const uid = window.GZ?.uid;
    const curStock = await window.dbGet?.(`businesses/${uid}/mainWarehouse/${code}_kb`) || 0;
    if (curStock < q) return window.toast?.(`Yeterli stok yok (${curStock} adet var)`, 'error');
    const caught = Math.random() < risk * 0.7;
    if (caught) {
      const ceza = Math.floor(satFiyat * q * 0.4);
      await window.spendCash?.(uid, ceza, 'karaborsa-ceza');
      await window.dbSet?.(`businesses/${uid}/mainWarehouse/${code}_kb`, Math.max(0, curStock - q));
      if (typeof window.updateKrediNotu === 'function') await window.updateKrediNotu(uid, -15, 'Kara borsa satış');
      await window.dbPush?.(`karaborsa/${uid}/log`, { type:'sell', code, caught:true, ts:Date.now() });
      window.toast?.(`🚔 MAL MÜSADERE! ${window.cashFmt?.(ceza)} ceza, stok sıfırlandı!`, 'error');
    } else {
      const gelir = satFiyat * q;
      await window.addCash?.(uid, gelir, 'karaborsa-sat');
      await window.dbSet?.(`businesses/${uid}/mainWarehouse/${code}_kb`, Math.max(0, curStock - q));
      await window.dbPush?.(`karaborsa/${uid}/log`, { type:'sell', code, amount:gelir, qty:q, ts:Date.now() });
      window.toast?.(`💰 +${window.cashFmt?.(gelir)} kara para aklandı`, 'success');
    }
    window.renderKaraborsa?.();
  };
};

/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 32 — GELİŞMİŞ OYUNCu PAZARI
   ══════════════════════════════════════════════════════════════════════════════ */

(function patchOyunPazari() {
  const _origRender = window.renderOyunPazari;
  window.renderOyunPazari = async function() {
    const main = document.getElementById('appMain');
    main.innerHTML = `
      <div class="page-title">🏬 Oyuncu Pazarı</div>
      <div class="subtabs">
        <button class="subtab active" onclick="oyunPazariView2('all',event)">🛒 Tüm İlanlar</button>
        <button class="subtab" onclick="oyunPazariView2('mine',event)">📦 İlanlarım</button>
        <button class="subtab" onclick="oyunPazariView2('sell',event)">➕ Sat</button>
        <button class="subtab" onclick="oyunPazariView2('history',event)">📜 Geçmiş</button>
      </div>
      <div id="oyunPazariList2"><div class="spinner" style="margin:20px auto"></div></div>`;
    window.oyunPazariView2('all');
  };

  window.oyunPazariView2 = async function(view, ev) {
    if (ev) { document.querySelectorAll('.subtab').forEach(b => b.classList.remove('active')); ev.target.classList.add('active'); }
    const list = document.getElementById('oyunPazariList2');
    if (!list) return;
    list.innerHTML = '<div class="spinner" style="margin:20px auto"></div>';
    const uid = window.GZ?.uid;
    const cf  = window.cashFmt || (n => n.toLocaleString('tr-TR')+'₺');

    if (view === 'all') {
      const ilanlar = await window.dbGet?.('playerMarket/listings').catch(()=>({})) || {};
      const arr = Object.values(ilanlar).filter(i => i.active && i.uid !== uid).sort((a,b) => (b.ts||0)-(a.ts||0));
      if (!arr.length) { list.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">📭 Aktif ilan yok. Kendi ürününü sat!</div>'; return; }
      list.innerHTML = arr.map(il => {
        const u = (window.URUNLER||{})[il.item] || {};
        const indirim = il.originalPrice > il.price ? Math.round((1-il.price/il.originalPrice)*100) : 0;
        return `<div class="card" style="margin-bottom:10px;border:1px solid var(--border,#e5e7eb)">
          <div style="display:flex;gap:10px;align-items:center">
            <span style="font-size:28px">${u.emo||'📦'}</span>
            <div style="flex:1">
              <div style="font-weight:700">${u.name||il.item}</div>
              <div style="font-size:11px;color:#64748b">
                Satıcı: <b>${il.sellerName||'Anonim'}</b> · ${il.qty||0} ${u.unit||'adet'}
                ${indirim > 0 ? `<span style="background:#dc2626;color:#fff;padding:1px 5px;border-radius:4px;font-size:10px;margin-left:4px">-%${indirim}</span>` : ''}
              </div>
            </div>
            <div style="text-align:right">
              <div style="font-size:18px;font-weight:700;color:#22c55e">${cf(il.price)}</div>
              <div style="font-size:10px;color:#64748b">/${u.unit||'adet'}</div>
            </div>
          </div>
          <div style="display:flex;gap:8px;margin-top:10px">
            <input type="number" id="pm_${il.id}" placeholder="Adet" min="1" max="${il.qty}"
              style="flex:1;padding:8px;border-radius:8px;border:1px solid var(--border,#e5e7eb);background:var(--bg,#fff);color:var(--text,#111);font-size:13px">
            <button style="padding:8px 16px;background:#22c55e;border:none;border-radius:8px;color:#fff;font-weight:700;cursor:pointer"
              onclick="window.oyunPazariAl?.('${il.id}', '${il.uid}', '${il.item}', ${il.price})">Satın Al</button>
          </div>
        </div>`;
      }).join('');

    } else if (view === 'mine') {
      const ilanlar = await window.dbGet?.(`playerMarket/byUser/${uid}`).catch(()=>({})) || {};
      const arr = Object.values(ilanlar).sort((a,b) => (b.ts||0)-(a.ts||0));
      if (!arr.length) { list.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">Henüz ilan vermedin.</div>'; return; }
      list.innerHTML = arr.map(il => {
        const u = (window.URUNLER||{})[il.item] || {};
        return `<div class="card" style="margin-bottom:10px;${il.active?'border:1px solid #22c55e44':'opacity:.6'}">
          <div style="display:flex;justify-content:space-between;align-items:center">
            <div>
              <div style="font-weight:700">${u.emo||'📦'} ${u.name||il.item}</div>
              <div style="font-size:12px;color:#64748b">${il.qty} adet · ${cf(il.price)} · ${il.active?'<span style="color:#22c55e">Aktif</span>':'<span style="color:#ef4444">Satıldı/Kapandı</span>'}</div>
            </div>
            ${il.active ? `<button style="padding:6px 12px;background:#dc2626;border:none;border-radius:8px;color:#fff;cursor:pointer;font-size:12px"
              onclick="window.oyunPazariKaldir?.('${il.id}')">Kaldır</button>` : ''}
          </div>
        </div>`;
      }).join('');

    } else if (view === 'sell') {
      const mainWH = await window.dbGet?.(`businesses/${uid}/mainWarehouse`).catch(()=>({})) || {};
      const items  = Object.entries(mainWH).filter(([k,v]) => v > 0 && (window.URUNLER||{})[k]);
      if (!items.length) { list.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">Deponda satılacak ürün yok. Üretim ya da dükkan reyon aktarımı yap.</div>'; return; }
      list.innerHTML = `
        <div class="card" style="margin-bottom:12px">
          <div style="font-weight:700;margin-bottom:12px">📦 Depondaki Ürünler</div>
          ${items.map(([itemKey, qty]) => {
            const u = (window.URUNLER||{})[itemKey] || {};
            return `<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding:8px;background:var(--bg2,#f8fafc);border-radius:8px">
              <span style="font-size:22px">${u.emo||'📦'}</span>
              <div style="flex:1">
                <div style="font-weight:600;font-size:13px">${u.name||itemKey}</div>
                <div style="font-size:11px;color:#64748b">Depoda: ${qty} ${u.unit||'adet'} · Taban: ${cf(u.base||0)}</div>
              </div>
              <div style="display:flex;gap:6px;align-items:center">
                <input type="number" id="pmq_${itemKey}" placeholder="Adet" min="1" max="${qty}"
                  style="width:70px;padding:6px;border-radius:6px;border:1px solid var(--border,#e5e7eb);background:var(--bg,#fff);color:var(--text,#111);font-size:12px">
                <input type="number" id="pmp_${itemKey}" placeholder="Fiyat" min="0" value="${+(u.base*1.1).toFixed(2)}"
                  style="width:80px;padding:6px;border-radius:6px;border:1px solid var(--border,#e5e7eb);background:var(--bg,#fff);color:var(--text,#111);font-size:12px">
                <button style="padding:6px 10px;background:#3b82f6;border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:11px;font-weight:700"
                  onclick="window.oyunPazariIlanVer?.('${itemKey}', ${qty})">İlan Ver</button>
              </div>
            </div>`;
          }).join('')}
        </div>`;

    } else if (view === 'history') {
      const log = await window.dbGet?.(`playerMarket/log/${uid}`).catch(()=>({})) || {};
      const arr = Object.values(log).sort((a,b) => (b.ts||0)-(a.ts||0)).slice(0,20);
      if (!arr.length) { list.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">Geçmiş işlem yok.</div>'; return; }
      list.innerHTML = `<div class="card">${arr.map(l => {
        const u = (window.URUNLER||{})[l.item] || {};
        return `<div style="display:flex;justify-content:space-between;font-size:12px;padding:8px 0;border-bottom:1px solid var(--border,#e5e7eb)11">
          <span>${l.type==='buy'?'🛒':'💰'} ${u.name||l.item} × ${l.qty}</span>
          <span style="color:${l.type==='sell'?'#22c55e':'#3b82f6'}">${l.type==='sell'?'+':'−'}${cf(l.total)}</span>
          <span style="color:#64748b">${new Date(l.ts||0).toLocaleDateString('tr-TR')}</span>
        </div>`;
      }).join('')}</div>`;
    }
  };

  window.oyunPazariAl = async function(ilanId, saticiUid, item, price) {
    const q = parseInt(document.getElementById('pm_'+ilanId)?.value) || 0;
    if (!q) return window.toast?.('Adet gir', 'error');
    const uid = window.GZ?.uid;
    const ilan = await window.dbGet?.(`playerMarket/listings/${ilanId}`).catch(()=>null);
    if (!ilan || !ilan.active) return window.toast?.('İlan mevcut değil', 'error');
    const maxQ = Math.min(q, ilan.qty);
    const total = price * maxQ;
    const ok = await window.spendCash?.(uid, total, 'player-market');
    if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
    // Satıcıya para
    await window.db?.ref(`users/${saticiUid}/money`).transaction(c => (c||0) + total * 0.95); // %5 komisyon
    // Alıcıya ürün
    const curStock = await window.dbGet?.(`businesses/${uid}/mainWarehouse/${item}`).catch(()=>0) || 0;
    await window.dbSet?.(`businesses/${uid}/mainWarehouse/${item}`, curStock + maxQ);
    // İlanı güncelle
    const newQty = (ilan.qty||0) - maxQ;
    await window.dbUpdate?.(`playerMarket/listings/${ilanId}`, { qty: newQty, active: newQty > 0 });
    await window.dbUpdate?.(`playerMarket/byUser/${saticiUid}/${ilanId}`, { qty: newQty, active: newQty > 0 });
    // Log
    await window.dbPush?.(`playerMarket/log/${uid}`, { type:'buy', item, qty:maxQ, total, ts:Date.now() });
    await window.dbPush?.(`playerMarket/log/${saticiUid}`, { type:'sell', item, qty:maxQ, total:total*0.95, ts:Date.now() });
    window.toast?.(`✅ ${maxQ} adet alındı — ${window.cashFmt?.(total)}`, 'success');
    window.oyunPazariView2?.('all');
  };

  window.oyunPazariIlanVer = async function(item, maxQty) {
    const uid = window.GZ?.uid;
    const q   = parseInt(document.getElementById('pmq_'+item)?.value) || 0;
    const p   = parseFloat(document.getElementById('pmp_'+item)?.value) || 0;
    if (!q || !p || q > maxQty) return window.toast?.('Geçersiz adet veya fiyat', 'error');
    if (p <= 0) return window.toast?.('Fiyat 0\'dan büyük olmalı', 'error');
    const curStock = await window.dbGet?.(`businesses/${uid}/mainWarehouse/${item}`).catch(()=>0) || 0;
    if (curStock < q) return window.toast?.('Yeterli depo stoğu yok', 'error');
    // Stok düş
    await window.db?.ref(`businesses/${uid}/mainWarehouse/${item}`).transaction(c => Math.max(0, (c||0)-q));
    const id = 'pm_'+Math.random().toString(36).slice(2,10);
    const ilanData = {
      id, uid, item, qty:q, price:p, active:true, ts:Date.now(),
      sellerName: window.GZ?.data?.username || 'Anonim',
      originalPrice: (window.URUNLER||{})[item]?.base || p
    };
    await window.dbSet?.(`playerMarket/listings/${id}`, ilanData);
    await window.dbSet?.(`playerMarket/byUser/${uid}/${id}`, ilanData);
    window.toast?.(`✅ İlan verildi: ${q} adet × ${window.cashFmt?.(p)}`, 'success');
    window.oyunPazariView2?.('mine');
  };

  window.oyunPazariKaldir = async function(ilanId) {
    const uid = window.GZ?.uid;
    const ilan = await window.dbGet?.(`playerMarket/byUser/${uid}/${ilanId}`).catch(()=>null);
    if (!ilan) return;
    // Ürünü depoya iade et
    if (ilan.qty > 0) {
      await window.db?.ref(`businesses/${uid}/mainWarehouse/${ilan.item}`).transaction(c => (c||0) + ilan.qty);
    }
    await window.dbUpdate?.(`playerMarket/listings/${ilanId}`, { active:false });
    await window.dbUpdate?.(`playerMarket/byUser/${uid}/${ilanId}`, { active:false });
    window.toast?.('İlan kaldırıldı, ürün depona iade edildi', 'success');
    window.oyunPazariView2?.('mine');
  };
})();

/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 33 — GELİŞMİŞ LOJİSTİK
   ══════════════════════════════════════════════════════════════════════════════ */

(function patchLojistik() {
  const _orig = window.renderLojistik;
  window.renderLojistik = async function() {
    const main = document.getElementById('appMain');
    main.innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner" style="margin:0 auto"></div></div>';
    const uid = window.GZ?.uid;
    const wh  = await window.dbGet?.(`businesses/${uid}/warehouses`).catch(()=>({})) || {};
    const mwh = await window.dbGet?.(`businesses/${uid}/mainWarehouse`).catch(()=>({})) || {};
    const cf  = window.cashFmt || (n => n.toLocaleString('tr-TR')+'₺');

    const totalMwhItems = Object.entries(mwh).filter(([k,v])=>v>0&&(window.URUNLER||{})[k]);
    const mwhTotal = totalMwhItems.reduce((s,[,v])=>s+v,0);

    main.innerHTML = `
      <div class="page-title">🚚 Lojistik Merkezi</div>

      <!-- Ana Depo -->
      <div class="card" style="background:linear-gradient(135deg,#0c1a2e,#0f2240);border:1px solid #1e3a5f;margin-bottom:12px">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
          <div>
            <div style="font-size:11px;color:#64748b">ANA DEPO (Merkez)</div>
            <div style="font-size:22px;font-weight:700">${mwhTotal.toLocaleString('tr-TR')} ürün</div>
          </div>
          <div style="font-size:36px">🏭</div>
        </div>
        ${totalMwhItems.length ? `
        <div style="max-height:200px;overflow-y:auto">
          ${totalMwhItems.map(([k,v]) => {
            const u = (window.URUNLER||{})[k] || {};
            return `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid #1e3a5f">
              <span>${u.emo||'📦'} ${u.name||k}</span>
              <div style="display:flex;align-items:center;gap:8px">
                <span style="font-weight:700">${v.toLocaleString('tr-TR')} ${u.unit||''}</span>
                <button style="padding:3px 8px;background:#3b82f6;border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:10px"
                  onclick="window.lojistikTransfer?.('${k}', ${v})">Aktar</button>
              </div>
            </div>`;
          }).join('')}
        </div>` : '<p style="color:#64748b;font-size:12px">Ana depo boş — üretim veya satın alma ile stok oluştur</p>'}
      </div>

      <!-- Şehir Depoları -->
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
        <div style="font-weight:700;font-size:14px">🏙️ Şehir Depoları</div>
        <button class="btn-primary" style="font-size:12px" onclick="window.lojistikYeniDepo?.()">+ Depo Aç</button>
      </div>

      ${Object.values(wh).length ? Object.values(wh).map(w => {
        const stock = w.stock || {};
        const stockArr = Object.entries(stock).filter(([k,v])=>v>0&&(window.URUNLER||{})[k]);
        const cap = w.capacity || 1000;
        const used = stockArr.reduce((s,[,v])=>s+v, 0);
        const pct = Math.min(100, Math.round(used/cap*100));
        return `<div class="card" style="margin-bottom:10px">
          <div style="display:flex;justify-content:space-between;margin-bottom:8px">
            <div>
              <div style="font-weight:700">📦 ${w.city||'?'} Deposu</div>
              <div style="font-size:11px;color:#64748b">Kapasite: ${used.toLocaleString()}/${cap.toLocaleString()} · %${pct} dolu</div>
            </div>
            <div style="color:#64748b;font-size:11px">${w.type==='premium'?'💎 Premium':'📦 Standart'}</div>
          </div>
          <div style="height:6px;background:#e5e7eb;border-radius:3px;margin-bottom:10px">
            <div style="width:${pct}%;height:100%;background:${pct>80?'#ef4444':pct>50?'#f59e0b':'#22c55e'};border-radius:3px"></div>
          </div>
          ${stockArr.length ? stockArr.map(([k,v]) => {
            const u = (window.URUNLER||{})[k]||{};
            return `<div style="display:flex;justify-content:space-between;font-size:12px;padding:3px 0">
              <span>${u.emo||'📦'} ${u.name||k}</span><span>${v} ${u.unit||''}</span></div>`;
          }).join('') : '<p style="font-size:12px;color:#64748b;margin:0">Boş depo</p>'}
        </div>`;
      }).join('') : '<div class="card" style="text-align:center;padding:24px;color:var(--text-muted)">Henüz şehir deposu yok. Üst sağdaki butona bas!</div>'}

      <div class="card" style="background:#0c1a2e;border:1px solid #1e3a5f;margin-top:12px">
        <div style="font-size:12px;color:#64748b;line-height:1.8">
          💡 <b>Lojistik İpuçları:</b><br>
          • Robot aktifse ana depo → reyona otomatik aktarır<br>
          • İhracat için önce ürünü ana depoya aktar<br>
          • Premium depo: 5.000 kapasite, standart: 1.000
        </div>
      </div>`;

    window.lojistikYeniDepo = function() {
      const iller = window.ILLER || ['İstanbul','Ankara','İzmir','Bursa','Antalya'];
      const opts = iller.map(c=>`<option>${c}</option>`).join('');
      window.showModal?.('🏭 Yeni Depo Aç', `
        <div class="input-group"><label>Şehir</label><select id="whCity">${opts}</select></div>
        <div style="display:flex;gap:8px;margin-top:12px">
          <button class="btn-primary" style="flex:1" onclick="window.buyWarehouse?.(document.getElementById('whCity').value,'cash').then(()=>{window.closeModal?.();window.renderLojistik?.()})">25.000 ₺</button>
          <button class="btn-secondary" style="flex:1" onclick="window.buyWarehouse?.(document.getElementById('whCity').value,'diamond').then(()=>{window.closeModal?.();window.renderLojistik?.()})">💎 100 Elmas</button>
        </div>`);
    };

    window.lojistikTransfer = function(item, maxQty) {
      const u = (window.URUNLER||{})[item] || {};
      const whs = Object.values(wh).filter(w => w.city);
      if (!whs.length) return window.toast?.('Önce bir şehir deposu aç', 'warn');
      const opts = whs.map(w => `<option value="${w.id}">${w.city}</option>`).join('');
      window.showModal?.(`📦 ${u.name||item} Aktar`, `
        <div class="input-group"><label>Hedef Depo</label><select id="ljtWhId">${opts}</select></div>
        <div class="input-group"><label>Miktar (maks ${maxQty})</label><input type="number" id="ljtQty" min="1" max="${maxQty}" value="${maxQty}"></div>
        <button class="btn-primary" style="width:100%;margin-top:12px" onclick="window.doLojistikTransfer?.('${item}')">Aktar</button>`);
    };

    window.doLojistikTransfer = async function(item) {
      const whId = document.getElementById('ljtWhId')?.value;
      const qty  = parseInt(document.getElementById('ljtQty')?.value) || 0;
      if (!qty || !whId) return window.toast?.('Miktar ve depo seçin', 'error');
      const curMwh = await window.dbGet?.(`businesses/${uid}/mainWarehouse/${item}`).catch(()=>0) || 0;
      if (curMwh < qty) return window.toast?.('Yeterli stok yok ana depoda', 'error');
      await window.db?.ref(`businesses/${uid}/mainWarehouse/${item}`).transaction(c => Math.max(0,(c||0)-qty));
      await window.db?.ref(`businesses/${uid}/warehouses/${whId}/stock/${item}`).transaction(c => (c||0)+qty);
      window.toast?.(`✅ ${qty} adet aktarıldı`, 'success');
      window.closeModal?.();
      window.renderLojistik?.();
    };
  };
})();

