// muhtarlik tab'ına gelenleri vergidairesi'ne yönlendir
window.renderMuhtarlik = function() {
  if (typeof window.renderVergiOyuncu === 'function') {
    window.renderVergiOyuncu();
  } else {
    const main = document.getElementById('appMain');
    if (main) main.innerHTML = window.emptyState?.('🏛️','Devlet & Kamu','Menüden Vergi Dairesi veya Kredi Ofisi\'ni seç') || '';
  }
};

// vergidairesi + krediofisi + konkurato switchTab handler
(function() {
  const _orig = window.switchTab;
  window.switchTab = function(tab) {
    if (_orig) _orig(tab);
    if (tab === 'vergidairesi' || tab === 'vergi') { window.renderVergiOyuncu?.(); }
    else if (tab === 'krediofisi' || tab === 'kredi') { window.renderKredi?.(); }
    else if (tab === 'konkurato') { window.renderKonkurato?.(); }
    else if (tab === 'karaborsa') { window.renderKaraborsa?.(); }
    else if (tab === 'oyunpazari') { window.renderOyunPazari?.(); }
    else if (tab === 'lojistik') { window.renderLojistik?.(); }
    else if (tab === 'magaza') { window.renderMagaza?.(); }
  };
})();

