/* ══════════════════════════════════════════════════════════════════════════════
   BÖLÜM 39 — GELIŞMIŞ KREDİ OFİSİ (tam detaylı)
   ══════════════════════════════════════════════════════════════════════════════ */

window.renderKredi = async function() {
  const main = document.getElementById('appMain');
  main.innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner" style="margin:0 auto"></div></div>';

  const uid   = window.GZ?.uid;
  const lv    = window.GZ?.data?.level || 1;
  const bank  = await window.dbGet?.(`bank/${uid}`).catch(()=>({})) || {};
  const mevcut = bank.loan || 0;
  const krediNotu = typeof window.getKrediNotu === 'function' ? await window.getKrediNotu(uid) : 50;
  const balance   = window.GZ?.data?.money || 0;
  const cf = window.cashFmt || (n => n.toLocaleString('tr-TR') + '₺');

  const BANKALAR = window.BANKALAR_MAP || {
    ziraat:  { name:'Ziraat Bankası',  emo:'🟢', faiz:0.032, maxCoef:12, minNote:40, minLv:1  },
    is:      { name:'İş Bankası',      emo:'🔵', faiz:0.028, maxCoef:18, minNote:50, minLv:3  },
    garanti: { name:'Garanti BBVA',    emo:'🟡', faiz:0.025, maxCoef:25, minNote:60, minLv:5  },
    akbank:  { name:'Akbank',          emo:'🔴', faiz:0.022, maxCoef:35, minNote:70, minLv:8  },
    yapi:    { name:'Yapı Kredi',      emo:'🟣', faiz:0.020, maxCoef:50, minNote:75, minLv:10 },
    ozel:    { name:'Özel Finans',     emo:'⚫', faiz:0.050, maxCoef:60, minNote:0,  minLv:1, note:'Yüksek faiz, düşük not gereksinimi' },
  };

  const weeklyGelir = window.GZ?.data?.weeklyRevenue || 0;
  const haftalikGelir = Math.max(weeklyGelir, lv * 500);

  // Kredi notu rengi
  const notRenk = krediNotu >= 80 ? '#22c55e' : krediNotu >= 60 ? '#f59e0b' : krediNotu >= 40 ? '#f97316' : '#ef4444';
  const notEtiket = krediNotu >= 80 ? 'Mükemmel' : krediNotu >= 60 ? 'İyi' : krediNotu >= 40 ? 'Orta' : 'Kötü';

  main.innerHTML = `
    <div class="page-title">💳 Kredi Ofisi</div>

    <!-- Kredi Durumu Kartı -->
    <div class="card" style="background:linear-gradient(135deg,rgba(15,24,48,0.9),rgba(10,16,36,0.95));border:1px solid rgba(59,130,246,0.3);margin-bottom:12px">
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;text-align:center">
        <div>
          <div style="font-size:10px;color:#64748b;font-weight:700;letter-spacing:.5px;text-transform:uppercase;margin-bottom:4px">KREDİ NOTU</div>
          <div style="font-size:32px;font-weight:900;color:${notRenk}">${krediNotu}</div>
          <div style="font-size:10px;font-weight:700;color:${notRenk}">${notEtiket}</div>
        </div>
        <div>
          <div style="font-size:10px;color:#64748b;font-weight:700;letter-spacing:.5px;text-transform:uppercase;margin-bottom:4px">MEVCUT BORÇ</div>
          <div style="font-size:22px;font-weight:800;color:${mevcut>0?'#ef4444':'#22c55e'}">${cf(mevcut)}</div>
          <div style="font-size:10px;color:#64748b">${mevcut>0?'Ödeme günü: Cumartesi':'Borçsuz 🎉'}</div>
        </div>
        <div>
          <div style="font-size:10px;color:#64748b;font-weight:700;letter-spacing:.5px;text-transform:uppercase;margin-bottom:4px">BAKİYE</div>
          <div style="font-size:22px;font-weight:800;color:#22c55e">${cf(balance)}</div>
          <div style="font-size:10px;color:#64748b">Anlık</div>
        </div>
      </div>
      <!-- Kredi notu çubuğu -->
      <div style="margin-top:14px">
        <div style="height:8px;background:rgba(255,255,255,0.06);border-radius:4px;overflow:hidden;margin-bottom:4px">
          <div style="width:${krediNotu}%;height:100%;background:linear-gradient(90deg,#ef4444,#f59e0b,#22c55e);border-radius:4px;box-shadow:0 0 10px ${notRenk}"></div>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:9px;color:#64748b"><span>0 — Kötü</span><span>50 — Orta</span><span>100 — Mükemmel</span></div>
      </div>
    </div>

    <!-- Banka Listesi -->
    <div style="font-weight:700;font-size:11px;color:#64748b;letter-spacing:1px;text-transform:uppercase;margin-bottom:10px">🏦 Bankalar & Kredi Ürünleri</div>

    ${Object.entries(BANKALAR).map(([key, b]) => {
      const locked    = lv < b.minLv || krediNotu < b.minNote;
      // Kredi limiti: haftalık gelir VEYA seviye bazlı minimum (hangisi büyükse)
      const levelBase  = lv * lv * 500;          // Lv1=500, Lv10=50k, Lv20=200k, Lv50=1.25M
      const gelirBase  = haftalikGelir * b.maxCoef;
      const maxKredi   = Math.max(levelBase, gelirBase);
      const aylikFaiz = (b.faiz / 12 * 100).toFixed(2);
      const borc12    = Math.floor(maxKredi * (1 + b.faiz)).toLocaleString('tr-TR');
      return `
      <div class="card" style="margin-bottom:8px;border:1px solid ${locked?'rgba(100,116,139,0.1)':'rgba(59,130,246,0.2)'};opacity:${locked?.5:1}">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:${locked?'0':'12px'}">
          <div style="font-size:28px;width:44px;height:44px;border-radius:10px;background:rgba(59,130,246,0.1);border:1px solid rgba(59,130,246,0.2);display:flex;align-items:center;justify-content:center">${b.emo}</div>
          <div style="flex:1">
            <div style="font-weight:700;font-size:14px">${b.name}</div>
            <div style="font-size:11px;color:#64748b">${locked?`🔒 Lv ${b.minLv}+ & Not ${b.minNote}+ gerekli`:(b.note||`Aylık %${aylikFaiz} faiz`)}</div>
          </div>
          <div style="text-align:right">
            <div style="font-size:18px;font-weight:800;color:#3b82f6">%${(b.faiz*100).toFixed(1)}</div>
            <div style="font-size:10px;color:#64748b">yıllık</div>
          </div>
        </div>
        ${locked ? '' : `
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px;font-size:11px">
          <div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:8px;text-align:center">
            <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase">Maks Kredi</div>
            <div style="font-weight:800;margin-top:2px;color:#3b82f6">${cf(maxKredi)}</div>
          </div>
          <div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:8px;text-align:center">
            <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase">12 Ay Toplam</div>
            <div style="font-weight:800;margin-top:2px;color:#f59e0b">${borc12}₺</div>
          </div>
          <div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:8px;text-align:center">
            <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase">Aylık Taksit</div>
            <div style="font-weight:800;margin-top:2px;color:#22c55e">${cf(Math.floor(maxKredi*(1+b.faiz)/12))}</div>
          </div>
        </div>
        <div style="display:flex;gap:8px;align-items:center">
          <input type="number" id="kredi_${key}" placeholder="Miktar gir..." min="1000" max="${maxKredi}"
            style="flex:1;padding:9px 12px;border-radius:9px;border:1px solid rgba(59,130,246,0.3);background:rgba(15,24,48,0.6);color:#e2e8f0;font-size:13px">
          <select id="vade_${key}" style="width:100px;padding:9px;border-radius:9px;border:1px solid rgba(59,130,246,0.3);background:rgba(15,24,48,0.6);color:#e2e8f0;font-size:12px">
            <option value="3">3 Ay</option>
            <option value="6">6 Ay</option>
            <option value="12" selected>12 Ay</option>
            <option value="24">24 Ay</option>
            <option value="36">36 Ay</option>
          </select>
          <button class="btn-primary" style="padding:9px 14px;font-size:12px;white-space:nowrap" onclick="krediBasvur('${key}')">Başvur</button>
        </div>`}
      </div>`;
    }).join('')}

    ${mevcut > 0 ? `
    <div class="card" style="background:rgba(220,38,38,0.08);border:1px solid rgba(239,68,68,0.25);margin-top:12px">
      <div style="font-weight:700;color:#fca5a5;margin-bottom:10px">💸 Mevcut Borç Ödemesi</div>
      <div style="font-size:13px;margin-bottom:10px;line-height:1.8;color:#e2e8f0">
        Kalan borç: <b style="color:#ef4444">${cf(mevcut)}</b><br>
        Haftalık otomatik kesinti aktif.<br>
        Erken ödeme = kredi notu +5
      </div>
      <div style="display:flex;gap:8px">
        <input type="number" id="odeme_miktar" placeholder="Erken ödeme miktarı" min="1"
          style="flex:1;padding:9px;border-radius:9px;border:1px solid rgba(239,68,68,0.3);background:rgba(15,24,48,0.6);color:#e2e8f0;font-size:13px">
        <button class="btn-danger" onclick="erkenOde()">Öde</button>
      </div>
    </div>` : ''}

    <div class="card" style="background:rgba(15,24,48,0.5);border:1px solid rgba(59,130,246,0.15);margin-top:12px">
      <div style="font-size:12px;color:#64748b;line-height:1.8">
        💡 <b style="color:#93c5fd">Kredi Notu Nasıl Yükselir?</b><br>
        ✅ Haftalık vergi/faiz ödemelerini zamanında yap<br>
        ✅ Borç yapılandırma taksitlerini düzenli öde<br>
        ✅ İşletme sayını artır<br>
        ❌ Ödeme kaçırma notunu düşürür<br>
        ❌ Kara borsa yakalanma ağır nota mal olur
      </div>
    </div>`;

  window.krediBasvur = async function(bankKey) {
    const b = BANKALAR[bankKey];
    if (!b) return;
    const miktar = parseFloat(document.getElementById('kredi_'+bankKey)?.value) || 0;
    const vade   = parseInt(document.getElementById('vade_'+bankKey)?.value) || 12;
    if (!miktar || miktar < 1000) return window.toast?.('Minimum 1.000₺ kredi alınabilir', 'warn');
    const maxK = haftalikGelir * b.maxCoef;
    if (miktar > maxK) return window.toast?.(`Bu bankada maks ${cf(maxK)} kredi alabilirsin`, 'error');
    if ((mevcut + miktar) > maxK * 1.5) return window.toast?.('Toplam borç limitini aşıyor', 'error');

    // Kredii hesabına yatır
    await window.db?.ref(`users/${uid}/money`).transaction(m => (m||0) + miktar);
    await window.db?.ref(`bank/${uid}/loan`).transaction(l => (l||0) + miktar);
    await window.dbUpdate?.(`bank/${uid}`, { loanBankId: bankKey, loanVade: vade, loanTs: Date.now() });
    if (typeof window.updateKrediNotu === 'function') await window.updateKrediNotu(uid, -2, 'Yeni kredi');
    window.toast?.(`✅ ${b.name}'dan ${cf(miktar)} kredi onaylandı! ${vade} aylık ödeme planı.`, 'success', 5000);
    setTimeout(() => window.renderKredi?.(), 1000);
  };

  window.erkenOde = async function() {
    const miktar = parseFloat(document.getElementById('odeme_miktar')?.value) || 0;
    if (!miktar || miktar < 1) return window.toast?.('Geçersiz miktar', 'error');
    const ok = await window.spendCash?.(uid, miktar, 'erken-odeme');
    if (!ok) return window.toast?.('Yetersiz bakiye', 'error');
    const yeni = Math.max(0, mevcut - miktar);
    await window.dbUpdate?.(`bank/${uid}`, { loan: yeni });
    if (typeof window.updateKrediNotu === 'function') await window.updateKrediNotu(uid, 5, 'Erken ödeme');
    window.toast?.(`✅ ${cf(miktar)} ödendi! Kredi notu +5. Kalan borç: ${cf(yeni)}`, 'success', 4000);
    setTimeout(() => window.renderKredi?.(), 800);
  };
};

